import { useState, useEffect, lazy, Suspense } from 'react';
import { Toaster } from 'react-hot-toast';
import Sidebar from './components/layout/Sidebar';
import Header from './components/layout/Header';
import { useUIStore } from './store/useUIStore';
import ErrorBoundary from './components/ErrorBoundary';

// ─── Code Splitting — cada página carrega só quando necessária (Tarefa 5.1) ───
const Dashboard    = lazy(() => import('./pages/Dashboard'));
const Notas        = lazy(() => import('./pages/Notas'));
const Study        = lazy(() => import('./pages/Study'));
const Flashcards   = lazy(() => import('./pages/Flashcards'));
const Graph        = lazy(() => import('./pages/Graph'));
const Statistics   = lazy(() => import('./pages/Statistics'));
const Settings     = lazy(() => import('./pages/Settings'));
const Poemas       = lazy(() => import('./pages/Poemas'));
const AIChat       = lazy(() => import('./pages/AIChat'));
const Gerador      = lazy(() => import('./pages/Gerador'));

// Fallback enquanto o chunk carrega
function PageLoader() {
  return (
    <div className="flex h-full w-full items-center justify-center">
      <div className="w-8 h-8 border-4 border-accent-main border-t-transparent rounded-full animate-spin" />
    </div>
  );
}

function App() {
  const [currentPage, setCurrentPage] = useState('dashboard');
  const { sidebarOpen, toggleSidebar, loading } = useUIStore();

  useEffect(() => {
    useUIStore.getState().init();

    const savedTema = localStorage.getItem('nexomente_tema') || 'dark';
    document.documentElement.classList.remove('dark', 'light');
    document.documentElement.classList.add(savedTema);
  }, []);

  useEffect(() => {
    const handleNavigate = (e) => {
      if (['dashboard', 'notes', 'study', 'flashcards', 'graph', 'statistics', 'settings', 'poemas', 'ai', 'gerador'].includes(e.detail)) {
        setCurrentPage(e.detail);
      }
    };
    window.addEventListener('navigate', handleNavigate);
    return () => window.removeEventListener('navigate', handleNavigate);
  }, []);

  // ── Atalhos de teclado globais (Tarefa 6.1) ──────────────────────────────
  const PAGES = ['dashboard', 'notes', 'study', 'flashcards', 'poemas', 'gerador', 'ai', 'graph', 'statistics', 'settings'];
  const pageIndex = PAGES.indexOf(currentPage);

  useEffect(() => {
    const ATALHOS = {
      '1': 'dashboard', '2': 'notes',      '3': 'study',
      '4': 'flashcards','5': 'gerador',    '6': 'ai',
      '7': 'graph',     '8': 'statistics', '9': 'settings',
    };
    const handler = (e) => {
      const tag = document.activeElement?.tagName;
      if (tag === 'INPUT' || tag === 'TEXTAREA' || document.activeElement?.isContentEditable) return;

      if ((e.ctrlKey || e.metaKey) && ATALHOS[e.key]) {
        e.preventDefault();
        setCurrentPage(ATALHOS[e.key]);
        return;
      }
      if ((e.ctrlKey || e.metaKey) && e.key === 'b') {
        e.preventDefault();
        toggleSidebar();
        return;
      }
      // Arrow keys for page navigation
      if (e.key === 'ArrowLeft' && pageIndex > 0) {
        e.preventDefault();
        setCurrentPage(PAGES[pageIndex - 1]);
      } else if (e.key === 'ArrowRight' && pageIndex < PAGES.length - 1) {
        e.preventDefault();
        setCurrentPage(PAGES[pageIndex + 1]);
      }
    };
    window.addEventListener('keydown', handler);
    return () => window.removeEventListener('keydown', handler);
  }, [toggleSidebar, currentPage, pageIndex]);


  if (loading) {
    return (
      <div className="flex h-full w-full bg-bg-primary items-center justify-center">
        <div className="text-center">
          <div className="w-12 h-12 border-4 border-accent-main border-t-transparent rounded-full animate-spin mx-auto mb-4"></div>
          <p className="text-text-secondary">Carregando NexoMente...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-full w-full bg-bg-primary">
      {/* Skip to main content link para navegação por teclado (Tarefa 6.7) */}
      <a 
        href="#main-content" 
        className="sr-only focus:not-sr-only focus:absolute focus:z-50 focus:p-4 focus:bg-bg-secondary focus:text-accent-main focus:rounded-br-lg"
      >
        Pular para o conteúdo principal
      </a>

      {/* Toast global — cobre toda a app (Tarefa 6.2) */}
      <Toaster
        position="bottom-right"
        toastOptions={{
          duration: 3000,
          style: {
            background: 'var(--bg-secondary, #1e1e2e)',
            color: 'var(--text-primary, #cdd6f4)',
            border: '1px solid var(--bg-tertiary, #313244)',
            fontSize: '0.875rem',
          },
          success: { iconTheme: { primary: '#a6e3a1', secondary: '#1e1e2e' } },
          error:   { iconTheme: { primary: '#f38ba8', secondary: '#1e1e2e' }, duration: 5000 },
        }}
      />

      <Sidebar
        isOpen={sidebarOpen}
        currentPage={currentPage}
        onNavigate={setCurrentPage}
      />

      <div className="flex flex-col flex-1 min-w-0">
        <Header
          title={currentPage}
          onToggleSidebar={toggleSidebar}
        />

        <main id="main-content" className="flex-1 overflow-auto focus:outline-none" tabIndex="-1">
          {/* ErrorBoundary por página + Suspense para lazy loading */}
          <ErrorBoundary context={currentPage}>
            <Suspense fallback={<PageLoader />}>
              {currentPage === 'dashboard'   && <Dashboard />}
              {currentPage === 'notes'       && <Notas />}
              {currentPage === 'study'       && <Study />}
              {currentPage === 'flashcards'  && <Flashcards />}
              {currentPage === 'graph'       && <Graph />}
              {currentPage === 'statistics'  && <Statistics />}
              {currentPage === 'settings'    && <Settings />}
              {currentPage === 'poemas'      && <Poemas />}
              {currentPage === 'ai'          && <AIChat onNavigate={setCurrentPage} />}
              {currentPage === 'gerador'     && <Gerador />}
            </Suspense>
          </ErrorBoundary>
        </main>
      </div>
    </div>
  );
}

export default App;

import { Component } from 'react';
import * as Sentry from '@sentry/react';

/**
 * Componente ErrorBoundary para capturar erros de renderização React.
 * Evita que um erro em um componente filho quebre toda a aplicação.
 *
 * @example
 * <ErrorBoundary context="Notas">
 *   <MinhaFuncionalidade />
 * </ErrorBoundary>
 */
class ErrorBoundary extends Component {
  constructor(props) {
    super(props);
    this.state = { hasError: false, error: null, errorInfo: null };
  }

  static getDerivedStateFromError(error) {
    return { hasError: true, error };
  }

  componentDidCatch(error, errorInfo) {
    // Log estruturado — integrado com Sentry na Fase 8
    console.error(`[ErrorBoundary:${this.props.context || 'App'}]`, error, errorInfo);

    if (import.meta.env.VITE_SENTRY_DSN) {
      Sentry.captureException(error, {
        tags: { context: this.props.context || 'App' },
        extra: { componentStack: errorInfo.componentStack }
      });
    }

    this.setState({ errorInfo });
  }

  handleReset = () => {
    this.setState({ hasError: false, error: null, errorInfo: null });
  };

  render() {
    if (this.state.hasError) {
      if (this.props.fallback) {
        return this.props.fallback(this.state.error, this.handleReset);
      }

      return (
        <div className="flex flex-col items-center justify-center h-full min-h-[200px] p-8 text-center">
          <div className="text-4xl mb-4">⚠️</div>
          <h2 className="text-text-primary text-lg font-semibold mb-2">
            Algo deu errado
          </h2>
          <p className="text-text-secondary text-sm mb-4 max-w-sm">
            {this.props.context
              ? `Ocorreu um erro em "${this.props.context}". `
              : ''}
            Tente novamente ou recarregue a página.
          </p>
          {import.meta.env.DEV && this.state.error && (
            <details className="text-left text-xs text-text-secondary bg-bg-secondary p-3 rounded mb-4 max-w-md w-full">
              <summary className="cursor-pointer font-mono mb-1">Detalhes do erro (dev)</summary>
              <pre className="overflow-auto whitespace-pre-wrap">
                {this.state.error.toString()}
                {this.state.errorInfo?.componentStack}
              </pre>
            </details>
          )}
          <button
            onClick={this.handleReset}
            className="px-4 py-2 bg-accent-main text-white rounded hover:opacity-80 transition-opacity text-sm"
          >
            Tentar novamente
          </button>
        </div>
      );
    }

    return this.props.children;
  }
}

export default ErrorBoundary;

/**
 * ChatMessage — bubble individual de mensagem no chat IA.
 * Extraído de AIChat.jsx (Tarefa 4.1).
 * Memoizado (Tarefa 5.4+5.5): evita re-render de mensagens antigas quando nova chega.
 */
import { memo } from 'react';
import { motion } from 'framer-motion';
import { Copy, Plus } from 'lucide-react';

const ChatMessage = memo(function ChatMessage({ msg, idx, copiadoIdx, onCopiar, onInserir }) {
  const isUser = msg.role === 'user';
  return (
    <motion.div
      initial={{ opacity: 0, y: 10 }}
      animate={{ opacity: 1, y: 0 }}
      className={`flex ${isUser ? 'justify-end' : 'justify-start'}`}
    >
      <div className={`max-w-[80%] rounded-xl px-4 py-3 ${
        isUser
          ? 'bg-accent-main/20 border border-accent-main/30 text-text-primary'
          : 'bg-bg-secondary border border-border-subtle text-text-primary'
      }`}>
        <p className="text-sm leading-relaxed whitespace-pre-wrap">{msg.texto}</p>
        {!isUser && (
          <div className="flex gap-1 mt-2 pt-2 border-t border-border-subtle">
            <button
              onClick={() => onCopiar(msg.texto, idx)}
              className="px-2 py-1 bg-bg-tertiary rounded text-[10px] hover:border-accent-main cursor-pointer flex items-center gap-1"
            >
              <Copy size={10} />
              {copiadoIdx === idx ? 'Copiado!' : 'Copiar'}
            </button>
            <button
              onClick={() => onInserir(msg.texto)}
              className="px-2 py-1 bg-bg-tertiary rounded text-[10px] hover:border-accent-main cursor-pointer flex items-center gap-1"
            >
              <Plus size={10} /> Inserir
            </button>
          </div>
        )}
      </div>
    </motion.div>
  );
});

export default ChatMessage;

import { useState } from 'react';
import { Tag, FileText, Layers, MoreHorizontal, Loader2, WifiOff } from 'lucide-react';
import { useAIModel } from '../../hooks/useAIModel';
import { checkLMStudioStatus, getModel } from '../../lib/ai/lmStudioService';

export default function AIBar({ nota, onTagsOpen, onResumoOpen, onCardsOpen, onChatOpen }) {
  const { status, modeloAtual } = useAIModel();
  const [showMore, setShowMore] = useState(false);

  if (!nota) return null;

  return (
    <div className="flex items-center gap-2 px-4 py-2 border-b border-border-subtle bg-bg-secondary/40">
      <div className="flex items-center gap-1">
        <button
          onClick={onTagsOpen}
          disabled={status === 'offline'}
          className="flex items-center gap-1.5 px-2.5 py-1 bg-bg-tertiary border border-border-subtle rounded text-xs hover:border-accent-main hover:text-accent-main disabled:opacity-40 disabled:cursor-not-allowed transition-colors cursor-pointer"
          title={status === 'offline' ? 'LM Studio offline' : 'Gerar tags com IA'}
        >
          <Tag size={12} />
          Tag#
        </button>

        <button
          onClick={onResumoOpen}
          disabled={status === 'offline'}
          className="flex items-center gap-1.5 px-2.5 py-1 bg-bg-tertiary border border-border-subtle rounded text-xs hover:border-accent-main hover:text-accent-main disabled:opacity-40 disabled:cursor-not-allowed transition-colors cursor-pointer"
          title={status === 'offline' ? 'LM Studio offline' : 'Gerar resumo com IA'}
        >
          <FileText size={12} />
          Resumir
        </button>

        <button
          onClick={onCardsOpen}
          disabled={status === 'offline'}
          className="flex items-center gap-1.5 px-2.5 py-1 bg-bg-tertiary border border-border-subtle rounded text-xs hover:border-accent-main hover:text-accent-main disabled:opacity-40 disabled:cursor-not-allowed transition-colors cursor-pointer"
          title={status === 'offline' ? 'LM Studio offline' : 'Gerar flashcards com IA'}
        >
          <Layers size={12} />
          Cards
        </button>

        <div className="relative">
          <button
            onClick={() => setShowMore(!showMore)}
            className="flex items-center gap-1.5 px-2.5 py-1 bg-bg-tertiary border border-border-subtle rounded text-xs hover:border-accent-main hover:text-accent-main transition-colors cursor-pointer"
            title="Mais ações"
          >
            <MoreHorizontal size={12} />
          </button>

          {showMore && (
            <>
              <div className="fixed inset-0 z-40" onClick={() => setShowMore(false)} />
              <div className="absolute top-full left-0 mt-1 bg-bg-secondary border border-border-subtle rounded-lg shadow-lg z-50 w-48 overflow-hidden">
                <button
                  onClick={() => { onChatOpen?.(); setShowMore(false); }}
                  className="w-full px-3 py-2 text-xs text-left hover:bg-bg-tertiary cursor-pointer"
                >
                  Chat sobre esta nota
                </button>
              </div>
            </>
          )}
        </div>
      </div>

      <div className="ml-auto flex items-center gap-1.5">
        {status === 'offline' ? (
          <div className="flex items-center gap-1 text-xs text-text-muted">
            <WifiOff size={10} />
            <span>IA offline</span>
          </div>
        ) : status === 'checking' ? (
          <Loader2 size={10} className="animate-spin text-text-muted" />
        ) : (
          <div
            className="text-[10px] text-text-muted truncate max-w-[120px]"
            title={modeloAtual}
          >
            {modeloAtual}
          </div>
        )}
      </div>
    </div>
  );
}

import { useState, useCallback } from 'react';
import { Sparkles, Loader2, Tag, FileText, Layers, RefreshCw, Check, X, Zap } from 'lucide-react';
import { checkLMStudioStatus, generate, setModel, getModel, suggestTags, summarizeContent, generateFlashcards } from '../../lib/ai/lmStudioService';

export default function AIPanel({ nota, onTagsUpdate, onResumoUpdate, onFlashcardsCreate }) {
  const [status, setStatus] = useState('checking');
  const [loading, setLoading] = useState(null);
  const [resultado, setResultado] = useState(null);
  const [error, setError] = useState(null);
  const [modelo, setModelo] = useState(getModel());

  const verificarStatus = useCallback(async () => {
    setStatus('checking');
    const res = await checkLMStudioStatus();
    setStatus(res.status);
  }, []);

  const handleGerarTags = async () => {
    if (!nota) return;
    setLoading('tags');
    setError(null);
    const tags = await suggestTags(nota);
    if (tags.length > 0) {
      onTagsUpdate(tags);
      setResultado({ tipo: 'tags', valor: tags });
    } else {
      setError('Não foi possível gerar tags');
    }
    setLoading(null);
  };

  const handleResumir = async () => {
    if (!nota) return;
    setLoading('resumo');
    setError(null);
    const resumo = await summarizeContent(nota.conteudo || '');
    if (resumo) {
      onResumoUpdate(resumo);
      setResultado({ tipo: 'resumo', valor: resumo });
    } else {
      setError('Não foi possível gerar resumo');
    }
    setLoading(null);
  };

  const handleGerarCards = async () => {
    if (!nota) return;
    setLoading('cards');
    setError(null);
    const cards = await generateFlashcards(nota, 3);
    if (cards.length > 0) {
      onFlashcardsCreate(cards);
      setResultado({ tipo: 'cards', valor: cards });
    } else {
      setError('Não foi possível gerar flashcards');
    }
    setLoading(null);
  };

  const handleUsarModelo = async (modeloId) => {
    setModel(modeloId);
    setModelo(modeloId);
    await verificarStatus();
  };

  return (
    <div className="bg-bg-secondary rounded-lg border border-border-subtle overflow-hidden">
      <div className="p-3 border-b border-border-subtle flex items-center justify-between">
        <div className="flex items-center gap-2">
          <Sparkles size={14} className="text-accent-light" />
          <span className="text-xs font-semibold text-text-primary">IA Local</span>
          <span
            className={`w-2 h-2 rounded-full ${
              status === 'online' ? 'bg-success' : status === 'checking' ? 'bg-warning animate-pulse' : 'bg-text-muted/40'
            }`}
          />
          {status === 'online' && <span className="text-[10px] text-success">online</span>}
          {status === 'offline' && <span className="text-[10px] text-text-muted">offline</span>}
        </div>
        <button
          onClick={verificarStatus}
          className="p-1 text-text-muted hover:text-accent-main cursor-pointer"
          title="Verificar conexão"
        >
          <RefreshCw size={12} />
        </button>
      </div>

      {status === 'offline' && (
        <div className="p-3 text-xs text-text-muted">
          LM Studio não está rodando em{' '}
          <span className="text-accent-main">127.0.0.1:1234</span>. Inicie o app e selecione um modelo.
        </div>
      )}

      {status === 'online' && (
        <div className="p-3 space-y-2">
          <p className="text-[10px] text-text-muted truncate">
            Modelo: <span className="text-accent-light">{modelo}</span>
          </p>

          {error && (
            <div className="flex items-center gap-1 text-xs text-danger bg-danger/10 rounded px-2 py-1">
              <X size={10} /> {error}
            </div>
          )}

          {resultado && (
            <div className="text-xs text-success bg-success/10 rounded px-2 py-1 flex items-center gap-1">
              <Check size={10} />{' '}
              {resultado.tipo === 'tags' && `+${resultado.valor.length} tags`}
              {resultado.tipo === 'resumo' && 'Resumo gerado'}
              {resultado.tipo === 'cards' && `+${resultado.valor.length} flashcards`}
            </div>
          )}

          <div className="grid grid-cols-3 gap-1">
            <button
              onClick={handleGerarTags}
              disabled={!nota || loading}
              className="flex flex-col items-center gap-0.5 px-2 py-2 bg-bg-tertiary rounded text-xs hover:border-accent-main border border-border-subtle disabled:opacity-40 cursor-pointer"
            >
              {loading === 'tags' ? <Loader2 size={12} className="animate-spin" /> : <Tag size={12} />}
              <span className="text-text-muted">Tags</span>
            </button>

            <button
              onClick={handleResumir}
              disabled={!nota || loading}
              className="flex flex-col items-center gap-0.5 px-2 py-2 bg-bg-tertiary rounded text-xs hover:border-accent-main border border-border-subtle disabled:opacity-40 cursor-pointer"
            >
              {loading === 'resumo' ? <Loader2 size={12} className="animate-spin" /> : <FileText size={12} />}
              <span className="text-text-muted">Resumo</span>
            </button>

            <button
              onClick={handleGerarCards}
              disabled={!nota || loading}
              className="flex flex-col items-center gap-0.5 px-2 py-2 bg-bg-tertiary rounded text-xs hover:border-accent-main border border-border-subtle disabled:opacity-40 cursor-pointer"
            >
              {loading === 'cards' ? <Loader2 size={12} className="animate-spin" /> : <Layers size={12} />}
              <span className="text-text-muted">Cards</span>
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

import { useState } from 'react';
import {
  FolderOpen, Plus, Folder, FileText, BookOpen, Lightbulb,
  Calendar, Bookmark, BookMarked, ChevronRight
} from 'lucide-react';

const tipoIcones = {
  pasta_raiz: FolderOpen,
  livros: BookOpen,
  projetos: Folder,
  ideias: Lightbulb,
  diario: Calendar,
  estudo: BookMarked,
  biblia: Bookmark,
  inbox: FileText,
};

const tipoCores = {
  pasta_raiz: '#6C63FF',
  livros: '#8B5CF6',
  projetos: '#3B82F6',
  ideias: '#EC4899',
  diario: '#10B981',
  estudo: '#F59E0B',
  biblia: '#F59E0B',
  inbox: '#9CA3AF',
};

export default function BibliotecaPanel({ pastas, notas, notaSelecionada, onMoverNota, onCriarPasta }) {
  const [categoriaExpandida, setCategoriaExpandida] = useState('pasta_raiz');
  const [novaPasta, setNovaPasta] = useState('');

  const categorias = [
    { id: 'pasta_raiz', nome: 'Todas', tipo: 'pasta_raiz' },
    { id: 'inbox', nome: 'Inbox', tipo: 'inbox' },
    { id: 'livros', nome: 'Livros', tipo: 'livros' },
    { id: 'projetos', nome: 'Projetos', tipo: 'projetos' },
    { id: 'ideias', nome: 'Ideias', tipo: 'ideias' },
    { id: 'estudo', nome: 'Estudo', tipo: 'estudo' },
    { id: 'biblia', nome: 'Bíblia', tipo: 'biblia' },
  ];

  const toggleCategoria = (id) => {
    setCategoriaExpandida(prev => prev === id ? null : id);
  };

  const notasPorCategoria = (catId) => {
    if (catId === 'pasta_raiz') return notas;
    if (catId === 'inbox') return notas.filter(n => !n.pasta_id || n.pasta_id === 'inbox');
    return notas.filter(n => n.tipo === catId);
  };

  const countCategoria = (catId) => {
    return notasPorCategoria(catId).length;
  };

  return (
    <div className="w-60 border-r border-border-subtle flex flex-col bg-bg-secondary">
      <div className="p-3 border-b border-border-subtle flex items-center justify-between">
        <span className="text-xs font-semibold text-text-muted uppercase tracking-wider">Bibliotecas</span>
        <button
          onClick={() => {
            const id = `pasta_${Date.now()}`;
            if (novaPasta.trim()) {
              onCriarPasta?.({ id, nome: novaPasta.trim(), tipo: 'pasta_raiz' });
              setNovaPasta('');
            } else {
              setNovaPasta('__new__');
            }
          }}
          className="p-1 hover:bg-bg-tertiary rounded text-text-muted hover:text-accent-main cursor-pointer"
          title="Nova biblioteca"
        >
          <Plus size={14} />
        </button>
      </div>

      {novaPasta === '__new__' && (
        <div className="px-3 py-2 border-b border-border-subtle">
          <input
            autoFocus
            type="text"
            value={novaPasta === '__new__' ? '' : novaPasta}
            onChange={(e) => setNovaPasta(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === 'Enter' && novaPasta.trim()) {
                onCriarPasta?.({ id: `pasta_${Date.now()}`, nome: novaPasta.trim(), tipo: 'pasta_raiz' });
                setNovaPasta('');
              } else if (e.key === 'Escape') {
                setNovaPasta('');
              }
            }}
            onBlur={() => {
              if (novaPasta.trim()) {
                onCriarPasta?.({ id: `pasta_${Date.now()}`, nome: novaPasta.trim(), tipo: 'pasta_raiz' });
              }
              setNovaPasta('');
            }}
            placeholder="Nome da biblioteca..."
            className="w-full bg-bg-tertiary border border-border-subtle rounded px-2 py-1 text-sm text-text-primary placeholder-text-muted focus:border-accent-main focus:outline-none"
          />
        </div>
      )}

      <div className="flex-1 overflow-auto py-1">
        {categorias.map(cat => {
          const Icon = tipoIcones[cat.id] || Folder;
          const cor = tipoCores[cat.id] || '#6C63FF';
          const count = countCategoria(cat.id);
          const expandida = categoriaExpandida === cat.id;
          const notasCat = notasPorCategoria(cat.id);

          return (
            <div key={cat.id}>
              <button
                onClick={() => toggleCategoria(cat.id)}
                className={`w-full px-3 py-2 flex items-center gap-2 text-sm hover:bg-bg-tertiary cursor-pointer ${
                  notaSelecionada?.pasta_id === cat.id || notaSelecionada?.tipo === cat.id
                    ? 'bg-bg-tertiary border-l-2'
                    : ''
                }`}
                style={{ borderLeftColor: notaSelecionada?.pasta_id === cat.id || notaSelecionada?.tipo === cat.id ? cor : 'transparent' }}
              >
                <ChevronRight
                  size={12}
                  className={`text-text-muted transition-transform ${expandida ? 'rotate-90' : ''}`}
                />
                <Icon size={14} style={{ color: cor }} />
                <span className="flex-1 text-left text-text-primary truncate">{cat.nome}</span>
                <span className="text-xs text-text-muted tabular-nums">{count}</span>
              </button>

              {expandida && notasCat.length > 0 && (
                <div className="ml-4 border-l border-border-subtle/50">
                  {notasCat.slice(0, 20).map(nota => {
                    const NotaIcon = tipoIcones[nota.tipo] || FileText;
                    const NotaCor = tipoCores[nota.tipo] || '#6C63FF';
                    return (
                      <button
                        key={nota.id}
                        onClick={() => onMoverNota?.(nota.id, cat.id)}
                        className={`w-full px-3 py-1.5 flex items-center gap-2 text-xs hover:bg-bg-tertiary cursor-pointer ${
                          notaSelecionada?.id === nota.id ? 'bg-accent-main/10' : ''
                        }`}
                        title={`Mover "${nota.titulo}" para ${cat.nome}`}
                      >
                        <NotaIcon size={10} style={{ color: NotaCor }} />
                        <span className="flex-1 text-left text-text-secondary truncate">
                          {nota.titulo}
                        </span>
                      </button>
                    );
                  })}
                  {notasCat.length > 20 && (
                    <p className="px-3 py-1 text-xs text-text-muted">
                      +{notasCat.length - 20} mais
                    </p>
                  )}
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
}

