import { useState, useEffect } from 'react';
import { X, Plus, Check, Loader2 } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { Tag } from 'lucide-react';

export default function TagPickerModal({ tagsSugeridas, loading, onConfirm, onCancel, modelo }) {
  const [selecionadas, setSelecionadas] = useState({});
  const [tagManual, setTagManual] = useState('');

  useEffect(() => {
    if (tagsSugeridas.length > 0) {
      const init = {};
      tagsSugeridas.forEach(t => { init[t] = true; });
      setSelecionadas(init);
    }
  }, [tagsSugeridas]);

  const toggle = (tag) => {
    setSelecionadas(prev => ({ ...prev, [tag]: !prev[tag] }));
  };

  const count = Object.values(selecionadas).filter(Boolean).length;

  const adicionarManual = () => {
    const tag = tagManual.toLowerCase().trim().replace(/\s+/g, '-').replace(/[^a-z0-9-]/g, '');
    if (!tag) return;
    setSelecionadas(prev => ({ ...prev, [tag]: true }));
    setTagManual('');
  };

  const handleConfirm = () => {
    const aceitas = Object.entries(selecionadas)
      .filter(([, v]) => v)
      .map(([tag]) => tag);
    onConfirm(aceitas);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
      <div className="fixed inset-0 bg-black/50 backdrop-blur-sm" onClick={onCancel} />
      <motion.div
        initial={{ opacity: 0, scale: 0.95 }}
        animate={{ opacity: 1, scale: 1 }}
        exit={{ opacity: 0, scale: 0.95 }}
        className="relative bg-bg-secondary border border-border-subtle rounded-xl w-full max-w-md overflow-hidden"
      >
        <div className="flex items-center justify-between p-4 border-b border-border-subtle">
          <div className="flex items-center gap-2">
            <Tag size={14} className="text-accent-light" />
            <span className="font-semibold text-text-primary">Tags sugeridas</span>
          </div>
          <div className="flex items-center gap-2">
            {modelo && (
              <span className="text-[10px] text-text-muted">{modelo}</span>
            )}
            <button
              onClick={onCancel}
              className="p-1 text-text-muted hover:text-text-primary cursor-pointer"
            >
              <X size={16} />
            </button>
          </div>
        </div>

        <div className="p-4 space-y-4 max-h-[400px] overflow-auto">
          {loading ? (
            <div className="flex items-center justify-center py-8">
              <Loader2 size={20} className="animate-spin text-accent-main" />
              <span className="ml-2 text-sm text-text-muted">Gerando tags...</span>
            </div>
          ) : tagsSugeridas.length === 0 ? (
            <p className="text-sm text-text-muted text-center py-4">
              Nenhuma tag gerada. Tente novamente.
            </p>
          ) : (
            <div className="flex flex-wrap gap-2">
              <AnimatePresence>
                {tagsSugeridas.map(tag => (
                  <motion.button
                    key={tag}
                    initial={{ opacity: 0, scale: 0.8 }}
                    animate={{ opacity: 1, scale: 1 }}
                    exit={{ opacity: 0, scale: 0.8 }}
                    onClick={() => toggle(tag)}
                    className={`flex items-center gap-1 px-2.5 py-1.5 rounded-full text-xs font-medium border transition-colors cursor-pointer ${
                      selecionadas[tag]
                        ? 'bg-accent-main/20 text-accent-main border-accent-main/40'
                        : 'bg-bg-tertiary text-text-secondary border-border-subtle hover:border-accent-main/40'
                    }`}
                  >
                    {selecionadas[tag] && <Check size={10} />}
                    #{tag}
                  </motion.button>
                ))}
              </AnimatePresence>
            </div>
          )}

          <div className="border-t border-border-subtle pt-4 space-y-2">
            <div className="flex items-center gap-2">
              <input
                type="text"
                value={tagManual}
                onChange={e => setTagManual(e.target.value)}
                onKeyDown={e => { if (e.key === 'Enter') adicionarManual(); }}
                placeholder="Adicionar tag manual..."
                className="flex-1 bg-bg-tertiary border border-border-subtle rounded px-3 py-1.5 text-sm focus:border-accent-main focus:outline-none"
              />
              <button
                onClick={adicionarManual}
                disabled={!tagManual.trim()}
                className="p-1.5 bg-bg-tertiary border border-border-subtle rounded hover:border-accent-main disabled:opacity-40 cursor-pointer"
              >
                <Plus size={14} />
              </button>
            </div>
          </div>
        </div>

        <div className="flex items-center justify-between p-4 border-t border-border-subtle">
          <button
            onClick={onCancel}
            className="px-4 py-2 bg-bg-tertiary border border-border-subtle rounded text-sm hover:border-accent-main transition-colors cursor-pointer"
          >
            Cancelar
          </button>
          <button
            onClick={handleConfirm}
            disabled={count === 0}
            className="px-4 py-2 bg-accent-main rounded text-sm font-medium hover:bg-accent-main/90 disabled:opacity-40 transition-colors cursor-pointer flex items-center gap-1"
          >
            <Check size={14} />
            Adicionar ({count})
          </button>
        </div>
      </motion.div>
    </div>
  );
}

/**
 * FlashcardViewer — área de revisão espaçada SM-2 do card atual.
 * Extraído de Flashcards.jsx (Tarefa 4.1).
 * Suporta navegação por teclado: Espaço (flip), 1/3/5 (review), Setas (navegar).
 */
import { useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Brain, RotateCcw, Check, X, ChevronLeft, ChevronRight, Edit } from 'lucide-react';

const QUALITY_LABELS = {
  1: { label: 'Errei', cor: '#EF4444' },
  3: { label: 'Quase', cor: '#F59E0B' },
  5: { label: 'Acertou', cor: '#10B981' },
};

export default function FlashcardViewer({
  cardAtual, paraRevisao, idxRevisao, mostrandoFrente,
  onViraCard, onRevisar, onAnterior, onProximo, onEditar, onCriar,
}) {
  useEffect(() => {
    if (!cardAtual) return;
    const handleKey = (e) => {
      if (['INPUT', 'TEXTAREA'].includes(document.activeElement?.tagName)) return;
      if (e.key === ' ' || e.key === 'Enter') { e.preventDefault(); onViraCard(); }
      else if (e.key === '1') { e.preventDefault(); onRevisar(1); }
      else if (e.key === '2' || e.key === '3') { e.preventDefault(); onRevisar(3); }
      else if (e.key === '5') { e.preventDefault(); onRevisar(5); }
      else if (e.key === 'ArrowLeft' || e.key === 'ArrowUp') { e.preventDefault(); onAnterior(); }
      else if (e.key === 'ArrowRight' || e.key === 'ArrowDown') { e.preventDefault(); onProximo(); }
      else if (e.key === 'e' || e.key === 'E') { e.preventDefault(); onEditar(cardAtual); }
    };
    window.addEventListener('keydown', handleKey);
    return () => window.removeEventListener('keydown', handleKey);
  }, [cardAtual, onViraCard, onRevisar, onAnterior, onProximo, onEditar]);

  if (!cardAtual) {
    return (
      <div className="bg-bg-secondary rounded-xl p-12 border border-border-subtle text-center">
        <Brain size={48} className="mx-auto mb-4 text-text-muted opacity-25" />
        <p className="text-lg text-text-primary">Nenhum card para revisar!</p>
        <p className="text-sm text-text-muted mt-1">Volte mais tarde ou crie novos cards</p>
        <button
          onClick={onCriar}
          className="mt-4 px-4 py-2 bg-accent-main rounded text-sm font-medium cursor-pointer"
        >
          Criar card
        </button>
      </div>
    );
  }

  return (
    <div className="bg-bg-secondary rounded-xl border border-border-subtle">
      {/* Conteúdo */}
      <div className="p-8 text-center">
        <p className="text-xs text-text-muted mb-4">
          {idxRevisao + 1} / {paraRevisao.length}
        </p>
        <AnimatePresence mode="wait">
          <motion.p
            key={`${cardAtual.id}-${mostrandoFrente}`}
            initial={{ opacity: 0, x: 20 }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: -20 }}
            className="text-xl font-semibold text-text-primary mb-8 leading-relaxed"
          >
            {mostrandoFrente ? cardAtual.frente : cardAtual.verso}
          </motion.p>
        </AnimatePresence>
        <button
          onClick={onViraCard}
          className="px-4 py-2 bg-bg-tertiary border border-border-subtle rounded text-sm cursor-pointer"
        >
          {mostrandoFrente ? 'Ver Resposta' : 'Ver Pergunta'}
        </button>
      </div>

      {/* Botões de qualidade */}
      <div className="border-t border-border-subtle p-4 flex justify-center gap-3">
        {Object.entries(QUALITY_LABELS).map(([q, info]) => (
          <button
            key={q}
            onClick={() => onRevisar(parseInt(q))}
            className="px-5 py-3 rounded-xl font-medium transition-colors cursor-pointer flex items-center gap-2"
            style={{ backgroundColor: `${info.cor}20`, border: `1px solid ${info.cor}40`, color: info.cor }}
          >
            {parseInt(q) === 1 ? <X size={16} /> : parseInt(q) === 3 ? <RotateCcw size={16} /> : <Check size={16} />}
            {info.label}
          </button>
        ))}
      </div>

      {/* Navegação */}
      <div className="border-t border-border-subtle p-3 flex justify-between items-center">
        <button
          onClick={onAnterior}
          disabled={idxRevisao === 0}
          className="p-2 text-text-muted hover:text-text-primary disabled:opacity-30 cursor-pointer"
        >
          <ChevronLeft size={18} />
        </button>
        <span className="text-xs text-text-muted">
          ef: {cardAtual.ef?.toFixed(1)} · streak: {cardAtual.repetitions}
        </span>
        <div className="flex gap-1">
          <button
            onClick={() => onEditar(cardAtual)}
            className="px-2 py-1 bg-bg-tertiary border border-border-subtle rounded text-xs text-text-muted hover:text-accent-main hover:border-accent-main cursor-pointer flex items-center gap-1"
          >
            <Edit size={12} /> Editar
          </button>
          <button
            onClick={onProximo}
            disabled={idxRevisao >= paraRevisao.length - 1}
            className="p-2 text-text-muted hover:text-text-primary disabled:opacity-30 cursor-pointer"
          >
            <ChevronRight size={18} />
          </button>
        </div>
      </div>
    </div>
  );
}

import { useEffect, useState } from 'react'
import { getXP, useUIStore } from '../store/useDBStore'

export default function XPTracker() {
  const xp = getXP()
  const level = useUIStore.getState().currentLevel
  const nextLevel = useUIStore.getState().nextLevel
  const progress = ((xp - level.xp) / nextLevel.xp) * 100

  useEffect(() => {
    console.log('XP Tracker initialized:', xp, 'Level', level.level)
  }, [xp, level])

  return (
    <div className="space-y-2">
      <div className="flex justify-between items-center text-sm">
        <span className="text-gray-600 font-medium">Nível {level.level}</span>
        <span className="text-gray-500">{xp}/{nextLevel.xp} XP</span>
      </div>
      <div className="h-2 bg-gray-200 rounded-full overflow-hidden">
        <div
          className="h-full bg-gradient-to-r from-blue-500 to-purple-600 transition-all duration-300"
          style={{ width: `${progress}%` }}
        />
      </div>
    </div>
  )
}

