                        title="Ler poema"
                      >
                        <Book size={16} />
                      </button>
                      <button 
                        onClick={() => iniciarEdicao(p)}
                        className="p-1.5 text-text-muted hover:text-text-primary rounded transition-colors"
                        title="Editar poema"
                      >
                        <Edit3 size={16} />
                      </button>
                      <button 
                        onClick={() => remove(p.id)}
                        className="p-1.5 text-text-muted hover:text-danger rounded transition-colors"
                        title="Excluir poema"
                      >
                        <Trash2 size={16} />
                      </button>
                    </div>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}

/**
 * Componente ConfirmDialog — diálogo de confirmação para ações destrutivas.
 * O botão de cancelar é o foco padrão para evitar exclusão acidental com Enter.
 *
 * @param {boolean} open - Se o dialog está visível
 * @param {string} title - Título da ação
 * @param {string} description - Descrição das consequências
 * @param {string} [confirmLabel='Confirmar'] - Label do botão de confirmação
 * @param {'default'|'destructive'} [confirmVariant='destructive'] - Variante do botão
 * @param {function} onConfirm - Callback quando o usuário confirma
 * @param {function} onCancel - Callback quando o usuário cancela
 */
function ConfirmDialog({
  open,
  title,
  description,
  confirmLabel = 'Confirmar',
  confirmVariant = 'destructive',
  onConfirm,
  onCancel,
}) {
  if (!open) return null;

  const handleBackdropClick = (e) => {
    if (e.target === e.currentTarget) onCancel?.();
  };

  const handleKeyDown = (e) => {
    if (e.key === 'Escape') onCancel?.();
  };

  const confirmStyles =
    confirmVariant === 'destructive'
      ? 'bg-red-600 hover:bg-red-700 text-white'
      : 'bg-accent-main hover:opacity-80 text-white';

  return (
    // eslint-disable-next-line jsx-a11y/no-noninteractive-element-interactions
    <div
      role="dialog"
      aria-modal="true"
      aria-labelledby="confirm-dialog-title"
      aria-describedby="confirm-dialog-desc"
      className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm"
      onClick={handleBackdropClick}
      onKeyDown={handleKeyDown}
    >
      <div className="bg-bg-secondary border border-bg-tertiary rounded-xl shadow-2xl p-6 max-w-sm w-full mx-4">
        <h2 id="confirm-dialog-title" className="text-text-primary font-semibold text-lg mb-2">
          {title}
        </h2>
        {description && (
          <p id="confirm-dialog-desc" className="text-text-secondary text-sm mb-6">
            {description}
          </p>
        )}
        <div className="flex gap-3 justify-end">
          {/* autoFocus no cancelar — evita exclusão acidental com Enter */}
          <button
            autoFocus
            onClick={onCancel}
            className="px-4 py-2 rounded-lg text-sm text-text-primary bg-bg-tertiary hover:bg-bg-primary transition-colors"
          >
            Cancelar
          </button>
          <button
            onClick={onConfirm}
            className={`px-4 py-2 rounded-lg text-sm font-medium transition-colors ${confirmStyles}`}
          >
            {confirmLabel}
          </button>
        </div>
      </div>
    </div>
  );
}

export default ConfirmDialog;

/**
 * Componente EmptyState — exibido quando uma lista ou área não tem conteúdo.
 * Evita que o usuário veja telas vazias sem contexto ou ação clara.
 *
 * @param {React.ReactNode} icon - Ícone representativo
 * @param {string} title - Título curto e claro
 * @param {string} description - Explicação e orientação
 * @param {React.ReactNode} [action] - CTA opcional (botão de criação, etc.)
 */
function EmptyState({ icon, title, description, action }) {
  return (
    <div className="flex flex-col items-center justify-center h-full min-h-[240px] p-8 text-center select-none">
      {icon && (
        <div className="text-text-secondary opacity-40 mb-4" style={{ fontSize: '3rem' }}>
          {icon}
        </div>
      )}
      <h3 className="text-text-primary font-semibold text-base mb-1">{title}</h3>
      {description && (
        <p className="text-text-secondary text-sm max-w-xs mb-4">{description}</p>
      )}
      {action && <div>{action}</div>}
    </div>
  );
}

export default EmptyState;

