import { useState, useEffect, useCallback } from 'react';
import { setModel as svcSetModel, setTemperature as svcSetTemp, getTemperature, getModel, checkLMStudioStatus } from '../lib/ai/lmStudioService';

export function useAIModel() {
  const [status, setStatus] = useState('checking');
  const [modelos, setModelos] = useState([]);
  const [modeloAtual, setModeloAtual] = useState(getModel());
  const [temperatura, setTemperatura] = useState(getTemperature());
  const [loading, setLoading] = useState(false);

  const verificar = useCallback(async () => {
    setLoading(true);
    setStatus('checking');
    try {
      const res = await checkLMStudioStatus();
      if (res.status === 'online') {
        setStatus('online');
        const mods = res.models.length > 0
          ? res.models.map(m => m.name || m)
          : [getModel()];
        setModelos(mods);
        if (!mods.includes(getModel())) {
          setModelos(prev => [...prev, getModel()]);
        }
      } else {
        setStatus('offline');
        setModelos([getModel()]);
      }
    } catch {
      setStatus('offline');
      setModelos([getModel()]);
    }
    setLoading(false);
  }, []);

  useEffect(() => {
    verificar();
  }, [verificar]);

  const trocarModelo = useCallback((novoModelo) => {
    svcSetModel(novoModelo);
    setModeloAtual(novoModelo);
    localStorage.setItem('nexomente_ai_model', novoModelo);
  }, []);

  const trocarTemperatura = useCallback((novaTemp) => {
    svcSetTemp(novaTemp);
    setTemperatura(novaTemp);
  }, []);

  return {
    status,
    modelos,
    modeloAtual,
    temperatura,
    loading,
    trocarModelo,
    trocarTemperatura,
    verificar,
  };
}

const CHAT_KEY_PREFIX = 'nexomente_ai_chat_';

export function useAIChat(notaId) {
  const [mensagens, setMensagens] = useState([]);
  const [loading, setLoading] = useState(false);
  const storageKey = notaId ? `${CHAT_KEY_PREFIX}${notaId}` : `${CHAT_KEY_PREFIX}livre`;

  useEffect(() => {
    const stored = localStorage.getItem(storageKey);
    if (stored) {
      try {
        setMensagens(JSON.parse(stored));
      } catch {
        setMensagens([]);
      }
    } else {
      setMensagens([]);
    }
  }, [storageKey]);

  const persistir = useCallback((msgs) => {
    const trimmed = msgs.slice(-40);
    localStorage.setItem(storageKey, JSON.stringify(trimmed));
    setMensagens(trimmed);
  }, [storageKey]);

  const adicionar = useCallback((role, texto) => {
    setMensagens(prev => {
      const updated = [...prev, { role, texto, ts: Date.now() }];
      persistir(updated);
      return updated;
    });
  }, [persistir]);

  const limpar = useCallback(() => {
    localStorage.removeItem(storageKey);
    setMensagens([]);
  }, [storageKey]);

  return { mensagens, adicionar, limpar, loading, setLoading };
}

import { useState, useEffect, useCallback } from 'react';
import sm2, { isParaRevisao, isDominado, SM2_DEFAULTS } from './sm2';

const FLASHCARDS_KEY = 'nexomente_flashcards';

export function useFlashcards() {
  const [cards, setCards] = useState(() => {
    const stored = localStorage.getItem(FLASHCARDS_KEY);
    if (stored) {
      try {
        return JSON.parse(stored);
      } catch {
        return [];
      }
    }
    return [];
  });
  const [loading, setLoading] = useState(false);

  const persist = useCallback((lista) => {
    localStorage.setItem(FLASHCARDS_KEY, JSON.stringify(lista));
    setCards(lista);
  }, []);

  const create = useCallback((cardData) => {
    const novoCard = {
      id: `card_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`,
      frente: cardData.frente,
      verso: cardData.verso,
      materia: cardData.materia || 'geral',
      tags: cardData.tags || [],
      ...SM2_DEFAULTS,
      created_at: new Date().toISOString(),
    };

    setCards(prev => {
      const updated = [...prev, novoCard];
      persist(updated);
      return updated;
    });
    return novoCard.id;
  }, [persist]);

  const update = useCallback((id, updates) => {
    setCards(prev => {
      const updated = prev.map(c => c.id === id ? { ...c, ...updates } : c);
      persist(updated);
      return updated;
    });
  }, [persist]);

  const remove = useCallback((id) => {
    setCards(prev => {
      const updated = prev.filter(c => c.id !== id);
      persist(updated);
      return updated;
    });
  }, [persist]);

  const revisar = useCallback((id, qualidade) => {
    setCards(prev => {
      const idx = prev.findIndex(c => c.id === id);
      if (idx === -1) return prev;

      const novosDados = sm2(prev[idx], qualidade);
      const updated = [...prev];
      updated[idx] = { ...updated[idx], ...novosDados };
      persist(updated);
      return updated;
    });
  }, [persist]);

  const getParaRevisao = useCallback(() => {
    return cards.filter(isParaRevisao);
  }, [cards]);

  const getDominados = useCallback(() => {
    return cards.filter(isDominado);
  }, [cards]);

  const getById = useCallback((id) => {
    return cards.find(c => c.id === id);
  }, [cards]);

  const stats = {
    total: cards.length,
    paraRevisar: getParaRevisao().length,
    dominados: getDominados().length,
  };

  return {
    cards,
    loading,
    create,
    update,
    remove,
    revisar,
    getParaRevisao,
    getDominados,
    getById,
    stats,
  };
}

import { useEffect, useCallback, useRef } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { useUIStore } from '../store/useUIStore';

export function useKeyboardShortcuts() {
  const navigate = useNavigate();
  const location = useLocation();
  const { toggleModoFoco } = useUIStore();

  const createQuickNota = useCallback(() => {
    if (location.pathname !== '/notas') navigate('/notas');
  }, [navigate, location]);

  const toggleFocusMode = useCallback(() => toggleModoFoco(), [toggleModoFoco]);

  const openCommandPalette = useCallback(() => {
    document.dispatchEvent(new CustomEvent('open-command-palette'));
  }, []);

  const showHelp = useCallback(() => {
    document.dispatchEvent(new CustomEvent('show-shortcuts-help'));
  }, []);

  const closeModals = useCallback(() => {
    document.dispatchEvent(new CustomEvent('close-modals'));
  }, []);

  // Mantém ref atualizada para o efeito não precisar de re-subscribe
  const shortcutsRef = useRef({});
  shortcutsRef.current = {
    'g d': () => navigate('/dashboard'),
    'g n': () => navigate('/notas'),
    'g s': () => navigate('/study'),
    'g f': () => navigate('/flashcards'),
    'g g': () => navigate('/graph'),
    'g t': () => navigate('/statistics'),
    'g ,': () => navigate('/settings'),
    'g q': () => navigate('/gerador'),
    'mod+shift+n': createQuickNota,
    'mod+shift+f': toggleFocusMode,
    'mod+k': openCommandPalette,
    'mod+/': showHelp,
    'escape': closeModals,
  };

  useEffect(() => {
    const handleKeyDown = (e) => {
      if (e.target.tagName === 'INPUT' || e.target.tagName === 'TEXTAREA') {
        return;
      }

      const keys = [];
      if (e.metaKey || e.ctrlKey) keys.push('mod');
      if (e.shiftKey) keys.push('shift');
      if (e.altKey) keys.push('alt');

      const key = e.key.toLowerCase();
      if (key !== 'meta' && key !== 'control' && key !== 'shift' && key !== 'alt') {
        keys.push(key);
      }

      const combo = keys.join('+');
      const action = shortcutsRef.current[combo];

      if (action) {
        e.preventDefault();
        action();
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [navigate, location]);
}

export const SHORTCUTS_LIST = [
  { keys: ['G', 'D'], action: 'Ir para Dashboard' },
  { keys: ['G', 'N'], action: 'Ir para Notas' },
