  { keys: ['G', ','], action: 'Ir para Configurações' },
  { keys: ['⌘', '⇧', 'N'], action: 'Nova nota rápida' },
  { keys: ['⌘', '⇧', 'F'], action: 'Alternar modo foco' },
  { keys: ['⌘', 'K'], action: 'Command palette' },
  { keys: ['⌘', '/'], action: 'Mostrar atalhos' },
  { keys: ['Esc'], action: 'Fechar modais' },
];

