import { useState, useEffect, useCallback } from 'react';

const STORAGE_KEY = 'nexomente_materias';

function generateId() {
  return `materia_${Date.now()}_${Math.random().toString(36).slice(2, 9)}`;
}

export function useMaterias() {
  const [materias, setMaterias] = useState([]);

  useEffect(() => {
    const stored = localStorage.getItem(STORAGE_KEY);
    if (stored) {
      try {
        setMaterias(JSON.parse(stored));
      } catch {
        setMaterias([]);
      }
    } else {
      const defaultMaterias = [
        { id: 'materia_default_1', nome: 'Português', cor: '#8B5CF6', icono: 'BookOpen', meta_horas: 10 },
        { id: 'materia_default_2', nome: 'Inglês', cor: '#3B82F6', icono: 'Globe', meta_horas: 8 },
        { id: 'materia_default_3', nome: 'Italiano', cor: '#10B981', icono: 'Globe', meta_horas: 5 },
        { id: 'materia_default_4', nome: 'Filosofia', cor: '#F59E0B', icono: 'Brain', meta_horas: 6 },
      ];
      setMaterias(defaultMaterias);
      localStorage.setItem(STORAGE_KEY, JSON.stringify(defaultMaterias));
    }
  }, []);

  const persist = useCallback((lista) => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(lista));
    setMaterias(lista);
  }, []);

  const create = useCallback((data = {}) => {
    const id = generateId();
    const nova = {
      id,
      nome: data.nome || 'Nova Matéria',
      cor: data.cor || '#6C63FF',
      icono: data.icono || 'BookOpen',
      meta_horas: data.meta_horas || 10,
      criado_em: new Date().toISOString(),
    };
    setMaterias(prev => {
      const updated = [...prev, nova];
      persist(updated);
      return updated;
    });
    return id;
  }, [persist]);

  const update = useCallback((id, data) => {
    setMaterias(prev => {
      const updated = prev.map(m => m.id === id ? { ...m, ...data } : m);
      persist(updated);
      return updated;
    });
  }, [persist]);

  const remove = useCallback((id) => {
    setMaterias(prev => {
      const updated = prev.filter(m => m.id !== id);
      persist(updated);
      return updated;
    });
  }, [persist]);

  const getById = useCallback((id) => {
    return materias.find(m => m.id === id) || null;
  }, [materias]);

  return { materias, create, update, remove, getById };
}

const POEMAS_KEY = 'nexomente_poemas';

export function usePoemas() {
  const [poemas, setPoemas] = useState([]);

  useEffect(() => {
    const stored = localStorage.getItem(POEMAS_KEY);
    if (stored) {
      try {
        setPoemas(JSON.parse(stored));
      } catch {
        setPoemas([]);
      }
    }
  }, []);

  const persist = useCallback((lista) => {
    localStorage.setItem(POEMAS_KEY, JSON.stringify(lista));
    setPoemas(lista);
  }, []);

  const create = useCallback((data = {}) => {
    const id = `poema_${Date.now()}_${Math.random().toString(36).slice(2, 9)}`;
    const novo = {
      id,
      titulo: data.titulo || 'Novo Poema',
      autor: data.autor || '',
      ano: data.ano || '',
      corpo: data.corpo || '',
      formato: data.formato || 'verso', // 'verso' | 'prosa'
      tags: data.tags || [],
      data_cadastro: new Date().toISOString(),
      ultima_recitacao: null,
      streak_recitacao: 0,
      total_recitacoes: 0,
    };
    setPoemas(prev => {
      const updated = [...prev, novo];
      persist(updated);
      return updated;
    });
    return id;
  }, [persist]);

  const update = useCallback((id, data) => {
    setPoemas(prev => {
      const updated = prev.map(p => p.id === id ? { ...p, ...data } : p);
      persist(updated);
      return updated;
    });
  }, [persist]);

  const remove = useCallback((id) => {
    setPoemas(prev => {
      const updated = prev.filter(p => p.id !== id);
      persist(updated);
      return updated;
    });
  }, [persist]);

  const registrarRecitacao = useCallback((id) => {
    setPoemas(prev => {
      const updated = prev.map(p => {
        if (p.id !== id) return p;
        const hoje = new Date().toISOString().split('T')[0];
        const ultima = p.ultima_recitacao;
        const streak = ultima === hoje ? p.streak_recitacao : p.streak_recitacao + 1;
        return {
          ...p,
          ultima_recitacao: hoje,
          streak_recitacao: streak,
          total_recitacoes: p.total_recitacoes + 1,
        };
      });
      persist(updated);
      return updated;
    });
  }, [persist]);

  const getById = useCallback((id) => poemas.find(p => p.id === id) || null, [poemas]);
  const proximoPoema = useCallback((atualId) => {
    const idx = poemas.findIndex(p => p.id === atualId);
    return idx < poemas.length - 1 ? poemas[idx + 1] : poemas[0];
  }, [poemas]);
  const poemaAnterior = useCallback((atualId) => {
    const idx = poemas.findIndex(p => p.id === atualId);
    return idx > 0 ? poemas[idx - 1] : poemas[poemas.length - 1];
  }, [poemas]);

  return { poemas, create, update, remove, registrarRecitacao, getById, proximoPoema, poemaAnterior };
}

/**
 * Hook useNotaEditor — encapsula toda a lógica do editor TipTap e das
 * ações de IA (tags, resumo, flashcards) que viviam em Notas.jsx.
 *
 * Extraído de Notas.jsx (Tarefa 4.1 — SRP / hooks extraction).
 *
 * @returns {{
 *   editor,
 *   aiLoadingTags, aiLoadingResumo, aiLoadingCards,
 *   tagsSugeridas, cardsSugeridos, resumoPreview,
 *   showTagPicker, showCardApprove,
 *   handleTagsOpen, handleResumoOpen, handleCardsOpen, handleChatOpen,
 *   handleTagsConfirm, handleCardsConfirm,
 *   setShowTagPicker, setShowCardApprove,
 *   salvarNota,
 * }}
 */
import { useState, useCallback, useEffect } from 'react';
import { useEditor } from '@tiptap/react';
import StarterKit from '@tiptap/starter-kit';
import Underline from '@tiptap/extension-underline';
import Link from '@tiptap/extension-link';
import Placeholder from '@tiptap/extension-placeholder';
import CodeBlock from '@tiptap/extension-code-block';
import Blockquote from '@tiptap/extension-blockquote';
import TaskList from '@tiptap/extension-task-list';
import TaskItem from '@tiptap/extension-task-item';
import Highlight from '@tiptap/extension-highlight';
import Mathematics from '@tiptap/extension-mathematics';
import 'katex/dist/katex.min.css';
import { suggestTags, summarizeContent, generateFlashcards } from '../lib/ai/lmStudioService';

export function useNotaEditor({ notaSelecionada, editando, update, addTag, setNotaSelecionada }) {
  const [showTagPicker, setShowTagPicker] = useState(false);
  const [showCardApprove, setShowCardApprove] = useState(false);
  const [aiLoadingTags, setAiLoadingTags] = useState(false);
  const [aiLoadingResumo, setAiLoadingResumo] = useState(false);
  const [aiLoadingCards, setAiLoadingCards] = useState(false);
  const [tagsSugeridas, setTagsSugeridas] = useState([]);
  const [cardsSugeridos, setCardsSugeridos] = useState([]);
  const [resumoPreview, setResumoPreview] = useState(null);

  const editor = useEditor({
    extensions: [
      StarterKit.configure({ codeBlock: false, blockquote: false, taskList: false, taskItem: false }),
      Underline,
      Link.configure({ openOnClick: false }),
      Placeholder.configure({ placeholder: 'Comece a escrever... [[nota]] para linkar' }),
      CodeBlock,
      Blockquote,
      TaskList,
      TaskItem.configure({ nested: true }),
      Highlight.configure({ multicolor: true }),
      Mathematics,
    ],
    content: '',
    editable: editando,
    editorProps: {
      attributes: {
        class: 'prose prose-invert max-w-none focus:outline-none min-h-[300px] p-6 leading-relaxed',
      },
    },
  });

  // Sincroniza conteúdo e modo edição quando a nota muda
  useEffect(() => {
    if (editor && notaSelecionada) {
      editor.commands.setContent(notaSelecionada.conteudo || '');
      editor.setEditable(editando);
    }
  }, [editor, notaSelecionada?.id, editando]);

  const salvarNota = useCallback(() => {
    if (!notaSelecionada || !editor) return;
    const conteudo = editor.getHTML();
    update(notaSelecionada.id, { titulo: notaSelecionada.titulo, conteudo });
  }, [notaSelecionada, editor, update]);

  const handleTagsOpen = useCallback(async () => {
    if (!notaSelecionada) return;
    setAiLoadingTags(true);
    const tags = await suggestTags(notaSelecionada, 8);
    setTagsSugeridas(tags);
    setAiLoadingTags(false);
    if (tags.length > 0) setShowTagPicker(true);
  }, [notaSelecionada]);

  const handleResumoOpen = useCallback(async () => {
    if (!notaSelecionada || !editor) return;
    setAiLoadingResumo(true);
    const resumo = await summarizeContent(notaSelecionada.conteudo || '');
    setResumoPreview(resumo);
    setAiLoadingResumo(false);
    if (resumo && window.confirm(`Resumo gerado:\n\n${resumo}\n\nInserir no topo da nota?`)) {
      editor.chain().focus().insertContentAt(0,
        `<blockquote class="ai-resumo"><p>${resumo.replace(/"/g, '&quot;')}</p></blockquote><p></p>`
      ).run();
      salvarNota();
    }
  }, [notaSelecionada, editor, salvarNota]);

  const handleCardsOpen = useCallback(async () => {
    if (!notaSelecionada) return;
    setAiLoadingCards(true);
    const cards = await generateFlashcards(notaSelecionada, 5);
    setCardsSugeridos(cards);
    setAiLoadingCards(false);
    if (cards.length > 0) setShowCardApprove(true);
  }, [notaSelecionada]);

  const handleChatOpen = useCallback(() => {
    window.dispatchEvent(new CustomEvent('navigate', { detail: 'ai' }));
  }, []);

  const handleTagsConfirm = useCallback((tagsAceitas) => {
    tagsAceitas.forEach(t => addTag(notaSelecionada.id, t));
    setNotaSelecionada(prev => ({ ...prev, tags: [...(prev.tags || []), ...tagsAceitas] }));
    setShowTagPicker(false);
  }, [notaSelecionada, addTag, setNotaSelecionada]);

  const handleCardsConfirm = useCallback(() => {
    setShowCardApprove(false);
  }, []);

  return {
    editor,
    aiLoadingTags, aiLoadingResumo, aiLoadingCards,
    tagsSugeridas, cardsSugeridos, resumoPreview,
    showTagPicker, showCardApprove,
    setShowTagPicker, setShowCardApprove,
    handleTagsOpen, handleResumoOpen, handleCardsOpen, handleChatOpen,
    handleTagsConfirm, handleCardsConfirm,
    salvarNota,
  };
}

