import { useState, useEffect, useRef, useCallback } from 'react';
import { useUIStore } from '../store/useUIStore';
import cytoscape from 'cytoscape';
import { GitBranch, ZoomIn, ZoomOut, Maximize2, Filter, Layout, Eye, EyeOff, X } from 'lucide-react';

const tipoCores = {
  nota: '#6C63FF',
  livro: '#8B5CF6',
  ideia: '#EC4899',
  diario: '#10B981',
  biblia: '#F59E0B',
  estudo: '#3B82F6',
  lembrete: '#EF4444',
};

export default function Graph() {
  const Notas = useUIStore.getState().Notas;
  const Pastas = useUIStore.getState().Pastas;
  const containerRef = useRef(null);
  const cyRef = useRef(null);
  const [notas, setNotas] = useState([]);
  const [notaSelecionada, setNotaSelecionada] = useState(null);
  const [layout, setLayout] = useState('cose');
  const [filtros, setFiltros] = useState({
    nota: true,
    livro: true,
    ideia: true,
    diario: true,
    biblia: true,
    estudo: true,
  });

  const extrairLinks = useCallback((conteudo) => {
    if (!conteudo) return [];
    const regex = /\[\[([^\]]+)\]\]/g;
    const links = [];
    let match;
    while ((match = regex.exec(conteudo)) !== null) {
      links.push(match[1]);
    }
    return links;
  }, []);

  const extrairTags = useCallback((nota) => {
    if (!nota.tags) return [];
    return Array.isArray(nota.tags) ? nota.tags : JSON.parse(nota.tags || '[]');
  }, []);

  useEffect(() => {
    setNotas(Notas.getAll());
  }, [Notas]);

  useEffect(() => {
    if (!containerRef.current || notas.length === 0) return;

    if (cyRef.current) {
      cyRef.current.destroy();
    }

    const elementos = [];

    notas.forEach(nota => {
      if (!filtros[nota.tipo]) return;

      elementos.push({
        data: { 
          id: nota.id, 
          label: nota.titulo || 'Sem título', 
          tipo: nota.tipo || 'nota',
          conteudo: nota.conteudo,
          tags: extrairTags(nota),
        },
      });
    });

    const tagsMap = {};
    notas.forEach(nota => {
      const tags = extrairTags(nota);
      tags.forEach(tag => {
        if (!tagsMap[tag]) tagsMap[tag] = [];
        tagsMap[tag].push(nota.id);
      });
    });

    Object.values(tagsMap).forEach(notaIds => {
      if (notaIds.length > 1) {
        for (let i = 0; i < notaIds.length - 1; i++) {
          elementos.push({
            data: {
              source: notaIds[i],
              target: notaIds[i + 1],
              tipo: 'tag',
            },
          });
        }
      }
    });

    notas.forEach(nota => {
      const links = extrairLinks(nota.conteudo);
      links.forEach(linkTexto => {
        const notaDestino = notas.find(n => 
          n.titulo?.toLowerCase() === linkTexto.toLowerCase()
        );
        if (notaDestino && notaDestino.id !== nota.id) {
          elementos.push({
            data: {
              source: nota.id,
              target: notaDestino.id,
              tipo: 'wikilink',
            },
          });
        }
      });
    });

    cyRef.current = cytoscape({
      container: containerRef.current,
      elements: elementos,
      style: [
        {
          selector: 'node',
          style: {
            'label': 'data(label)',
            'background-color': '#6C63FF',
            'color': '#F2F0FF',
            'font-size': '12px',
            'text-valign': 'bottom',
            'text-margin-y': 8,
            'width': 40,
            'height': 40,
          },
        },
        ...Object.entries(tipoCores).map(([tipo, cor]) => ({
          selector: `node[tipo="${tipo}"]`,
          style: { 'background-color': cor },
        })),
        {
          selector: 'edge[tipo="wikilink"]',
          style: {
            'width': 3,
            'line-color': '#6C63FF',
            'target-arrow-color': '#6C63FF',
            'target-arrow-shape': 'triangle',
            'curve-style': 'bezier',
          },
        },
        {
          selector: 'edge[tipo="tag"]',
          style: {
            'width': 1,
            'line-color': '#4A4A6A',
            'target-arrow-color': '#4A4A6A',
            'target-arrow-shape': 'triangle',
            'line-style': 'dashed',
          },
        },
        {
          selector: 'node:selected',
          style: {
            'border-width': 3,
            'border-color': '#F2F0FF',
          },
        },
      ],
      layout: { name: layout },
      minZoom: 0.3,
      maxZoom: 3,
      wheelSensitivity: 0.3,
    });

    cyRef.current.on('tap', 'node', (evt) => {
      const node = evt.target;
      const nota = notas.find(n => n.id === node.id());
      if (nota) {
        setNotaSelecionada(nota);
      }
    });

    return () => {
      if (cyRef.current) {
        cyRef.current.destroy();
      }
    };
  }, [notas, filtros, layout, extrairLinks, extrairTags]);

  const zoomIn = () => cyRef.current?.zoom(cyRef.current.zoom() * 1.2);
  const zoomOut = () => cyRef.current?.zoom(cyRef.current.zoom() / 1.2);
  const reset = () => cyRef.current?.fit();

  return (
    <div className="h-full flex flex-col">
      <div className="p-4 border-b border-border-subtle flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold text-text-primary">Grafo</h1>
          <p className="text-text-secondary">{notas.length} notas • {notas.filter(n => extrairLinks(n.conteudo).length)} conexões</p>
        </div>

        <div className="flex items-center gap-2">
          <button onClick={zoomIn} className="p-2 bg-bg-secondary border border-border-subtle rounded-lg hover:border-accent-main">
            <ZoomIn size={20} />
          </button>
          <button onClick={zoomOut} className="p-2 bg-bg-secondary border border-border-subtle rounded-lg hover:border-accent-main">
            <ZoomOut size={20} />
          </button>
          <button onClick={reset} className="p-2 bg-bg-secondary border border-border-subtle rounded-lg hover:border-accent-main">
            <Maximize2 size={20} />
          </button>
        </div>
      </div>

      <div className="p-4 border-b border-border-subtle flex gap-2">
        <select 
          value={layout} 
          onChange={(e) => setLayout(e.target.value)}
          className="px-3 py-1 bg-bg-secondary border border-border-subtle rounded-lg text-sm"
        >
          <option value="cose">COSE (automático)</option>
          <option value="circle">Círculo</option>
          <option value="grid">Grade</option>
          <option value="concentric">Concêntrico</option>
          <option value="breadthfirst">Árvore</option>
        </select>

        <Filter size={16} className="text-text-muted" />
        {Object.keys(filtros).map(tipo => (
          <button
            key={tipo}
            onClick={() => setFiltros(f => ({ ...f, [tipo]: !f[tipo] }))}
            className={`px-3 py-1 rounded-lg text-sm flex items-center gap-1 ${
              filtros[tipo] 
                ? '' 
                : 'opacity-50'
            }`}
            style={{ 
              backgroundColor: filtros[tipo] ? tipoCores[tipo] || '#6C63FF' : '#252338',
              border: `1px solid ${tipoCores[tipo] || '#6C63FF'}40`
            }}
          >
            {tipo.charAt(0).toUpperCase() + tipo.slice(1)}
          </button>
        ))}
      </div>

      {notaSelecionada && (
        <div className="absolute top-20 right-4 w-80 bg-bg-secondary border border-border-subtle rounded-xl p-4 shadow-xl z-10">
          <div className="flex justify-between items-start mb-2">
            <h3 className="font-bold">{notaSelecionada.titulo}</h3>
            <button onClick={() => setNotaSelecionada(null)}>
              <X size={16} />
            </button>
          </div>
          <p className="text-sm text-text-secondary line-clamp-4">
            {notaSelecionada.conteudo?.substring(0, 200)}
          </p>
          {extrairTags(notaSelecionada).length > 0 && (
            <div className="flex flex-wrap gap-1 mt-2">
              {extrairTags(notaSelecionada).map(tag => (
                <span key={tag} className="px-2 py-0.5 bg-accent-main/20 text-accent-main rounded text-xs">
                  {tag}
                </span>
              ))}
            </div>
          )}
        </div>
      )}

      {notas.length === 0 ? (
        <div className="flex-1 flex items-center justify-center text-text-muted">
          <div className="text-center">
            <GitBranch size={48} className="mx-auto mb-4 opacity-30" />
            <p className="text-lg">Nenhuma nota ainda</p>
            <p className="text-sm">Crie notas para ver as conexões</p>
          </div>
        </div>
      ) : (
        <div ref={containerRef} className="flex-1 bg-bg-primary" />
      )}
    </div>
  );
}

/**
 * NotasPage — página principal de notas do NexoMente.
 *
 * Refatorado (Tarefa 4.1): lógica extraída para:
 *   - useNotaEditor  → editor TipTap + ações de IA
 *   - NotaLista      → painel lateral de busca/listagem
 */
import { useState, useMemo } from 'react';
import { EditorContent } from '@tiptap/react';
import { FileText, Trash2 } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { useNotes } from '../hooks/useNotes';
import { useFlashcards } from '../hooks/useFlashcards';
import { useNotaEditor } from '../hooks/useNotaEditor';
import NotaLista from '../components/editor/NotaLista';
import EditorToolbar from '../components/editor/EditorToolbar';
import BibliotecaPanel from '../components/editor/BibliotecaPanel';
import NoteMetadata from '../components/editor/NoteMetadata';
import TagInput from '../components/editor/TagInput';
import AIPanel from '../components/editor/AIPanel';
import AIBar from '../components/editor/AIBar';
import TagPickerModal from '../components/editor/TagPickerModal';
import FlashcardApproveModal from '../components/editor/FlashcardApproveModal';
import { getModel } from '../lib/ai/lmStudioService';

export default function NotasPage() {
  const { notas, create, update, remove, search, getById, addTag, removeTag } = useNotes();
  const { create: createCard } = useFlashcards();

  const [notaSelecionada, setNotaSelecionada] = useState(null);
  const [editando, setEditando] = useState(false);
  const [criando, setCriando] = useState(false);
  const [busca, setBusca] = useState('');
  const [focoMode, setFocoMode] = useState(false);
  const [mostrandoTags, setMostrandoTags] = useState(false);
  const [mostrandoMeta, setMostrandoMeta] = useState(false);
  const [mostrandoAI, setMostrandoAI] = useState(false);

  const {
    editor,
    aiLoadingTags, aiLoadingResumo, aiLoadingCards,
    tagsSugeridas, cardsSugeridos,
    showTagPicker, showCardApprove,
    setShowTagPicker, setShowCardApprove,
    handleTagsOpen, handleResumoOpen, handleCardsOpen, handleChatOpen,
    handleTagsConfirm, handleCardsConfirm,
    salvarNota: _salvarNota,
  } = useNotaEditor({ notaSelecionada, editando, update, addTag, setNotaSelecionada });

  const notasFiltradas = useMemo(
    () => (busca ? search(busca) : notas),
    [notas, busca, search]
  );

  const criarNota = (tipo = 'nota') => {
    const id = create({ titulo: 'Nova Nota', tipo, pasta_id: 'inbox', status: 'inbox' });
    const nova = getById(id);
    setNotaSelecionada(nova);
    setEditando(true);
    setCriando(true);
  };

  const salvarNota = () => {
    _salvarNota();
    setEditando(false);
    setCriando(false);
  };

  const excluirNota = (id) => {
    remove(id);
    if (notaSelecionada?.id === id) {
      setNotaSelecionada(null);
      setEditando(false);
    }
  };

  return (
    <div className={`flex h-full ${focoMode ? 'bg-bg-primary' : ''}`}>
      {/* Painel lateral — lista de notas */}
      <AnimatePresence>
        {!focoMode && (
          <motion.div
            initial={{ width: 0, opacity: 0 }}
            animate={{ width: 240, opacity: 1 }}
            exit={{ width: 0, opacity: 0 }}
            transition={{ duration: 0.2 }}
            className="border-r border-border-subtle flex flex-col bg-bg-secondary overflow-hidden"
          >
            <NotaLista
              notas={notasFiltradas}
              notaSelecionada={notaSelecionada}
              busca={busca}
              onBuscaChange={setBusca}
              onSelect={(nota) => { setNotaSelecionada(nota); setEditando(false); }}
              onCriar={criarNota}
            />
          </motion.div>
        )}
      </AnimatePresence>

      {/* Painel biblioteca */}
      {!focoMode && (
        <BibliotecaPanel
          pastas={[]}
          notas={notas}
          notaSelecionada={notaSelecionada}
          onMoverNota={(notaId, pastaId) => {
            update(notaId, { pasta_id: pastaId });
            if (notaSelecionada?.id === notaId) setNotaSelecionada(getById(notaId));
          }}
          onCriarPasta={() => {}}
        />
      )}

      {/* Área principal do editor */}
      <div className="flex-1 flex flex-col min-w-0">
        {notaSelecionada ? (
          <>
            {/* Barra de título + ações */}
            {!focoMode && (
              <div className="p-3 border-b border-border-subtle flex items-center gap-2 bg-bg-secondary/50">
                <input
                  type="text"
                  value={notaSelecionada.titulo}
                  onChange={(e) => setNotaSelecionada({ ...notaSelecionada, titulo: e.target.value })}
                  className="flex-1 bg-transparent text-lg font-bold text-text-primary focus:outline-none"
                  placeholder="Título da nota"
                />
                {['IA', 'Info', 'Tags'].map((label) => {
                  const show = label === 'IA' ? mostrandoAI : label === 'Info' ? mostrandoMeta : mostrandoTags;
                  const toggle = label === 'IA'
                    ? () => setMostrandoAI(p => !p)
                    : label === 'Info'
                      ? () => setMostrandoMeta(p => !p)
                      : () => setMostrandoTags(p => !p);
                  return (
                    <button key={label} onClick={toggle}
                      className={`px-3 py-1.5 rounded text-xs border transition-colors cursor-pointer ${
                        show ? 'bg-accent-main text-white border-accent-main'
                             : 'bg-bg-tertiary text-text-secondary border-border-subtle hover:border-accent-main'
                      }`}
                    >{label}</button>
                  );
                })}
                {editando ? (
                  <button onClick={salvarNota}
                    className="px-3 py-1.5 bg-success rounded text-xs font-medium hover:bg-success/90 transition-colors cursor-pointer">
                    Salvar
                  </button>
                ) : (
                  <button onClick={() => setEditando(true)}
                    className="px-3 py-1.5 bg-accent-main rounded text-xs font-medium hover:bg-accent-main/90 transition-colors cursor-pointer">
                    Editar
                  </button>
                )}
                <button onClick={() => excluirNota(notaSelecionada.id)}
                  className="p-1.5 text-text-muted hover:text-danger transition-colors cursor-pointer">
                  <Trash2 size={14} />
                </button>
              </div>
            )}

            {/* Barra de tags */}
            {mostrandoTags && (
              <div className="px-4 py-2 border-b border-border-subtle bg-bg-secondary/30">
                <TagInput
                  tags={notaSelecionada.tags || []}
                  onAdd={(tag) => {
                    addTag(notaSelecionada.id, tag);
                    setNotaSelecionada(prev => ({ ...prev, tags: [...(prev.tags || []), tag] }));
                  }}
                  onRemove={(tag) => {
                    removeTag(notaSelecionada.id, tag);
                    setNotaSelecionada(prev => ({ ...prev, tags: (prev.tags || []).filter(t => t !== tag) }));
                  }}
                />
              </div>
            )}

            <EditorToolbar editor={editor} focusMode={focoMode} onToggleFocus={() => setFocoMode(p => !p)} />
            <AIBar nota={notaSelecionada}
              onTagsOpen={handleTagsOpen} onResumoOpen={handleResumoOpen}
              onCardsOpen={handleCardsOpen} onChatOpen={handleChatOpen}
            />

            <div className={`flex-1 overflow-auto ${focoMode ? 'max-w-3xl mx-auto w-full px-8 py-12' : ''}`}>
              <EditorContent editor={editor} className="h-full" />
            </div>
          </>
        ) : (
          <div className="flex-1 flex items-center justify-center text-text-muted">
            <div className="text-center">
              <FileText size={48} className="mx-auto mb-4 opacity-25" />
              <p className="text-lg">Selecione uma nota</p>
              <p className="text-sm mt-1">ou crie uma nova</p>
            </div>
          </div>
        )}
      </div>

      {/* Painéis laterais opcionais */}
      {mostrandoAI && notaSelecionada && (
        <div className="w-64 border-l border-border-subtle bg-bg-secondary overflow-auto">
          <AIPanel
            nota={notaSelecionada}
            onTagsUpdate={(tags) => {
              tags.forEach(t => addTag(notaSelecionada.id, t));
              setNotaSelecionada(prev => ({ ...prev, tags: [...(prev.tags || []), ...tags] }));
            }}
            onResumoUpdate={(resumo) => {
              update(notaSelecionada.id, { resumo_ia: resumo });
              setNotaSelecionada(prev => ({ ...prev, resumo_ia: resumo }));
            }}
            onFlashcardsCreate={(cards) => {
              cards.forEach(c => createCard({ frente: c.frente, verso: c.verso, materia: notaSelecionada.tipo }));
            }}
          />
        </div>
      )}

      {mostrandoMeta && notaSelecionada && (
        <NoteMetadata
          nota={notaSelecionada}
          onUpdate={(data) => {
            update(notaSelecionada.id, data);
            setNotaSelecionada(prev => ({ ...prev, ...data }));
          }}
        />
      )}

      {/* Modais de IA */}
      {showTagPicker && (
        <TagPickerModal
          tagsSugeridas={tagsSugeridas} loading={aiLoadingTags}
          onConfirm={handleTagsConfirm} onCancel={() => setShowTagPicker(false)}
          modelo={getModel()}
        />
      )}
      {showCardApprove && (
        <FlashcardApproveModal
          cards={cardsSugeridos} loading={aiLoadingCards}
          onCancel={() => setShowCardApprove(false)}
          modelo={getModel()} notaTitulo={notaSelecionada?.titulo}
        />
      )}
    </div>
  );
}

import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useUIStore } from '../store/useUIStore';
import { Brain, BookOpen, Calendar, Zap, ArrowRight, Check } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

const steps = [
  {
    id: 'welcome',
    title: 'Bem-vindo ao NexoMente',
    description: 'Seu segundo cérebro offline. Notas, flashcards, estudo e gamificação em um só lugar.',
    icon: Brain,
    color: '#6C63FF'
  },
  {
    id: 'notes',
    title: 'Notas Conectadas',
    description: 'Crie notas com wiki-links [[like this]]. O grafo mostra como tudo se conecta.',
    icon: BookOpen,
    color: '#F28E2B'
  },
  {
    id: 'study',
    title: 'Estudo Espaçado',
    description: 'Flashcards com algoritmo SM-2. Estude menos, lembre mais.',
    icon: Calendar,
    color: '#59A14F'
  },
  {
    id: 'complete',
    title: 'Pronto!',
    description: 'Você ganhou 50 XP só por começar. Vamos lá?',
    icon: Zap,
    color: '#EDC948'
  }
];

export function Onboarding() {
  const navigate = useNavigate();
  const [currentStep, setCurrentStep] = useState(0);
  const { completeOnboarding } = useUIStore();

  const handleNext = () => {
    if (currentStep < steps.length - 1) {
      setCurrentStep(currentStep + 1);
    } else {
      completeOnboarding();
      navigate('/dashboard');
    }
  };

  const handleSkip = () => {
    completeOnboarding();
    navigate('/dashboard');
  };

  const step = steps[currentStep];
  const Icon = step.icon;
  const isLast = currentStep === steps.length - 1;

  return (
    <div className="min-h-screen bg-[var(--bg-primary)] flex items-center justify-center p-4">
      <div className="max-w-md w-full">
        <motion.div
          key={currentStep}
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          exit={{ opacity: 0, y: -20 }}
          className="text-center"
        >
          <div 
            className="w-20 h-20 rounded-2xl flex items-center justify-center mx-auto mb-6"
            style={{ backgroundColor: step.color + '20' }}
          >
            <Icon size={40} style={{ color: step.color }} />
          </div>

          <h1 className="text-2xl font-bold text-[var(--text-primary)] mb-2">
            {step.title}
          </h1>

          <p className="text-[var(--text-secondary)] mb-8">
            {step.description}
          </p>

          <div className="flex justify-center gap-2 mb-8">
            {steps.map((_, i) => (
              <div
                key={i}
                className={`w-2 h-2 rounded-full transition-colors ${
                  i === currentStep 
                    ? 'bg-[var(--accent-main)]' 
                    : 'bg-[var(--border-subtle)]'
                }`}
              />
            ))}
          </div>

          <div className="flex gap-3">
            <button
              onClick={handleSkip}
              className="flex-1 py-3 px-4 rounded-xl text-[var(--text-secondary)] hover:text-[var(--text-primary)] transition-colors"
            >
              Pular
            </button>
            <button
              onClick={handleNext}
              className="flex-1 py-3 px-4 rounded-xl bg-[var(--accent-main)] text-white font-medium flex items-center justify-center gap-2 hover:opacity-90 transition-opacity"
            >
              {isLast ? (
                <>
                  <Check size={20} />
                  Começar
                </>
              ) : (
                <>
                  Próximo
                  <ArrowRight size={20} />
                </>
              )}
            </button>
          </div>
        </motion.div>
      </div>
    </div>
  );
}

