import { useState, useEffect, useCallback } from 'react';
import { useUIStore } from '../store/useUIStore';
import { useMaterias } from '../hooks/useMaterias';
import { Play, Pause, RotateCcw, Clock, BookOpen, Plus, Check, Trash2 } from 'lucide-react';

const MODOS = [
  { id: 'pomodoro', label: 'Pomodoro', minutos: 25 },
  { id: 'foco', label: 'Foco', minutos: 50 },
  { id: 'livre', label: 'Livre', minutos: 15 },
];

function formatarTempo(segundos) {
  const m = Math.floor(segundos / 60);
  const s = segundos % 60;
  return `${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
}

export default function Study() {
  const { materias, create, update, remove } = useMaterias();
  const Sessoes = useUIStore.getState().Sessoes;
  const XP = useUIStore.getState().XP;

  const [timer, setTimer] = useState(25 * 60);
  const [rodando, setRodando] = useState(false);
  const [materiaAtiva, setMateriaAtiva] = useState(null);
  const [sessaoId, setSessaoId] = useState(null);
  const [modo, setModo] = useState('pomodoro');
  const [novaMateria, setNovaMateria] = useState('');
  const [novaCor, setNovaCor] = useState('#6C63FF');
  const [showCriar, setShowCriar] = useState(false);
  const [sessoesList, setSessoesList] = useState([]);

  useEffect(() => {
    setSessoesList(Sessoes.getAll());
  }, []);

  useEffect(() => {
    let interval;
    if (rodando && timer > 0) {
      interval = setInterval(() => setTimer(t => t - 1), 1000);
    } else if (timer === 0 && rodando) {
      setRodando(false);
      if (sessaoId) {
        Sessoes.completar(sessaoId);
        XP.add(10, 'Sessão de estudo concluída', 'sessao', sessaoId);
        setSessoesList(Sessoes.getAll());
      }
    }
    return () => clearInterval(interval);
  }, [rodando, timer, sessaoId]);

  const iniciar = () => {
    const id = Sessoes.create({ materia_id: materiaAtiva, tipo: modo, duracao_minutos: Math.floor(timer / 60) });
    setSessaoId(id);
    setRodando(true);
  };

  const pausar = () => setRodando(false);
  const reiniciar = () => {
    setRodando(false);
    const m = MODOS.find(x => x.id === modo) || MODOS[0];
    setTimer(m.minutos * 60);
  };

  const criarMateria = () => {
    if (!novaMateria.trim()) return;
    create({ nome: novaMateria.trim(), cor: novaCor, meta_horas: 5 });
    setNovaMateria('');
    setShowCriar(false);
  };

  const sessoesHoje = sessoesList.filter(s => {
    if (!s.started_at) return false;
    return new Date(s.started_at).toDateString() === new Date().toDateString();
  });
  const minutosHoje = sessoesHoje.reduce((acc, s) => acc + (s.concluida ? s.duracao_minutos : 0), 0);

  const coresDisponiveis = ['#6C63FF', '#8B5CF6', '#EC4899', '#10B981', '#F59E0B', '#3B82F6', '#EF4444', '#06B6D4'];

  return (
    <div className="p-6 space-y-6">
      <div>
        <h1 className="text-2xl font-bold text-text-primary">Estudo</h1>
        <p className="text-sm text-text-muted">Pomodoro + matérias</p>
      </div>

      <div className="bg-bg-secondary rounded-xl p-8 border border-border-subtle text-center">
        <div className="text-7xl font-bold text-text-primary mb-6 font-mono">
          {formatarTempo(timer)}
        </div>

        <div className="flex justify-center gap-3 mb-6">
          {!rodando ? (
            <button onClick={iniciar} className="px-8 py-3 bg-success rounded-xl text-lg font-semibold hover:bg-success/90 transition-colors cursor-pointer flex items-center gap-2">
              <Play size={24} /> Iniciar
            </button>
          ) : (
            <button onClick={pausar} className="px-8 py-3 bg-warning rounded-xl text-lg font-semibold hover:bg-warning/90 transition-colors cursor-pointer flex items-center gap-2">
              <Pause size={24} /> Pausar
            </button>
          )}
          <button onClick={reiniciar} className="px-4 py-3 bg-bg-tertiary border border-border-subtle rounded-xl hover:border-accent-main transition-colors cursor-pointer">
            <RotateCcw size={24} />
          </button>
        </div>

        <div className="flex justify-center gap-2">
          {MODOS.map(m => (
            <button key={m.id} onClick={() => { setModo(m.id); reiniciar(); }}
              className={`px-4 py-2 rounded-lg text-sm font-medium cursor-pointer ${
                modo === m.id ? 'bg-accent-main' : 'bg-bg-tertiary border border-border-subtle hover:border-accent-main'
              }`}>
              {m.label} ({m.minutos}m)
            </button>
          ))}
        </div>
      </div>

      <div className="bg-bg-secondary rounded-xl p-4 border border-border-subtle">
        <div className="flex items-center justify-between mb-3">
          <h2 className="font-semibold text-text-primary">Matérias</h2>
          <button onClick={() => setShowCriar(!showCriar)}
            className="p-1 text-text-muted hover:text-accent-main cursor-pointer">
            <Plus size={18} />
          </button>
        </div>

        {showCriar && (
          <div className="mb-4 p-3 bg-bg-tertiary rounded-lg border border-border-subtle space-y-2">
            <input
              type="text"
              value={novaMateria}
              onChange={e => setNovaMateria(e.target.value)}
              placeholder="Nome da matéria..."
              onKeyDown={e => e.key === 'Enter' && criarMateria()}
              className="w-full bg-bg-secondary border border-border-subtle rounded px-3 py-1.5 text-sm focus:border-accent-main focus:outline-none"
            />
            <div className="flex items-center gap-2">
              {coresDisponiveis.map(cor => (
                <button
                  key={cor}
                  onClick={() => setNovaCor(cor)}
                  className={`w-6 h-6 rounded-full cursor-pointer ${novaCor === cor ? 'ring-2 ring-white ring-offset-1 ring-offset-bg-tertiary' : ''}`}
                  style={{ backgroundColor: cor }}
                />
              ))}
              <button onClick={criarMateria}
                className="ml-auto px-4 py-1.5 bg-accent-main rounded text-xs font-medium cursor-pointer">
                Criar
              </button>
            </div>
          </div>
        )}

        <div className="flex flex-wrap gap-2">
          <button
            onClick={() => setMateriaAtiva(null)}
            className={`px-3 py-1.5 rounded-lg text-sm cursor-pointer ${
              !materiaAtiva ? 'bg-accent-main' : 'bg-bg-tertiary border border-border-subtle hover:border-accent-main'
            }`}>
            Todas
          </button>
          {materias.map(m => (
            <div key={m.id} className="group flex items-center gap-1">
              <button
                onClick={() => setMateriaAtiva(m.id)}
                className={`px-3 py-1.5 rounded-lg text-sm cursor-pointer ${
                  materiaAtiva === m.id ? 'bg-accent-main' : 'bg-bg-tertiary border border-border-subtle hover:border-accent-main'
                }`}
                style={{ borderLeftColor: m.cor, borderLeftWidth: '3px', borderLeftStyle: 'solid' }}>
                {m.nome}
              </button>
              <button
                onClick={() => remove(m.id)}
                className="p-1 text-text-muted hover:text-danger opacity-0 group-hover:opacity-100 transition-opacity cursor-pointer">
                <Trash2 size={12} />
              </button>
            </div>
          ))}
        </div>
      </div>

      <div className="grid grid-cols-2 gap-4">
        <div className="bg-bg-secondary rounded-xl p-4 border border-border-subtle text-center">
          <Clock className="text-accent-main mx-auto mb-2" size={24} />
          <p className="text-2xl font-bold text-text-primary">{minutosHoje}</p>
          <p className="text-sm text-text-muted">min hoje</p>
        </div>
        <div className="bg-bg-secondary rounded-xl p-4 border border-border-subtle text-center">
          <Check className="text-success mx-auto mb-2" size={24} />
          <p className="text-2xl font-bold text-text-primary">
            {sessoesHoje.filter(s => s.concluida).length}
          </p>
          <p className="text-sm text-text-muted">sessões concluídas</p>
        </div>
      </div>

      <div className="bg-bg-secondary rounded-xl p-4 border border-border-subtle">
        <h3 className="font-semibold text-text-primary mb-3 text-sm">Progresso por Matéria</h3>
        {materias.length === 0 ? (
          <p className="text-sm text-text-muted">Crie uma matéria para acompanhar progresso</p>
        ) : (
          <div className="space-y-3">
            {materias.map(m => {
              const min = sessoesList
                .filter(s => s.materia_id === m.id && s.concluida)
                .reduce((acc, s) => acc + (s.duracao_minutos || 0), 0);
              const progresso = Math.min(100, Math.round((min / ((m.meta_horas || 5) * 60)) * 100));
              return (
                <div key={m.id} className="space-y-1">
                  <div className="flex justify-between text-xs">
                    <span className="text-text-primary flex items-center gap-1.5">
                      <span className="w-2 h-2 rounded-full" style={{ backgroundColor: m.cor }} />
                      {m.nome}
                    </span>
                    <span className="text-text-muted">{min}m / {m.meta_horas * 60}m</span>
                  </div>
                  <div className="h-2 bg-bg-tertiary rounded-full overflow-hidden">
                    <div
                      className="h-full rounded-full transition-all duration-500"
                      style={{ width: `${progresso}%`, backgroundColor: m.cor }}
                    />
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}

import { buildOutput } from '../lib/iaPrompts';

export function exportarParaTexto(questoes, opcoes = {}) {
  const {
    titulo = 'Banco de Questões',
    incluirGabarito = true,
    incluirJustificativas = true,
    formato = 'completo',
  } = opcoes;

  let conteudo = `═══════════════════════════════════════════════════════════════════
         ${titulo.toUpperCase()}
         Gerado em: ${new Date().toLocaleDateString('pt-BR')} | Questões: ${questoes.length}
═══════════════════════════════════════════════════════════════════
`;

  questoes.forEach((q, idx) => {
    const num = String(idx + 1).padStart(3, '0');
    conteudo += '\n';
    conteudo += buildOutput(q, num, formato);
    conteudo += '\n═══════════════════════════════════════════════════════════════════';
  });

  if (incluirGabarito) {
    conteudo += '\n\n';
    conteudo += '───────────────────────────────────────────────────\n';
    conteudo += '                    GABARITO\n';
    conteudo += '───────────────────────────────────────────────────\n';

    questoes.forEach((q, idx) => {
      conteudo += `${String(idx + 1).padStart(3, '0')} - ${q.resposta_correta || '?'}  (${q.materia}) ${q.topico ? `| ${q.topico}` : ''}\n`;
    });
  }

  return conteudo;
}

export function exportarParaHTML(questoes, opcoes = {}) {
  const {
    titulo = 'Banco de Questões',
    estilo = 'prova',
    incluirJustificativas = true,
  } = opcoes;

  const css = `
    body { font-family: 'Times New Roman', serif; font-size: 12pt; line-height: 1.5; margin: 2cm; }
    h1 { text-align: center; font-size: 14pt; margin-bottom: 20px; }
    .questao { margin-bottom: 20px; page-break-inside: avoid; }
    .questao-num { font-weight: bold; }
    .enunciado { margin: 10px 0; }
    .alternativas { margin-left: 20px; }
    .alternativa { margin: 5px 0; }
    .gabarito { color: #006400; font-weight: bold; }
    .separador { border-top: 1px solid #000; margin: 20px 0; }
  `;

  let html = `<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>${titulo}</title>
  <style>${css}</style>
</head>
<body>
  <h1>${titulo}</h1>
`;

  if (estilo === 'prova') {
    questoes.forEach((q, idx) => {
      const num = idx + 1;
      html += `
  <div class="questao">
    <div class="questao-num">[${num}] ${q.materia}${q.topico ? ` - ${q.topico}` : ''}</div>
    <div class="enunciado">${q.pergunta}</div>
    <div class="alternativas">
      ${q.opcoes.map(o => `<div class="alternativa">(${o.letra}) ${o.texto}</div>`).join('\n      ')}
    </div>
  </div>
  <div class="separador"></div>
`;
    });
  } else {
    questoes.forEach((q, idx) => {
      const num = idx + 1;
      const correta = q.opcoes.find(o => o.correta);

      html += `
  <div class="questao">
    <div class="questao-num">[${num}] ${q.pergunta}</div>
    <div class="alternativas">
      ${q.opcoes.map(o => `<div class="alternativa${o.correta ? ' gabarito' : ''}">(${o.letra}) ${o.texto}</div>`).join('\n      ')}
    </div>
    ${incluirJustificativas && correta ? `
    <div class="justificativa"><strong>Justificativa:</strong> ${correta.justificativa_correta || ''}</div>
    ` : ''}
  </div>
`;
    });
  }

  html += `
</body>
</html>`;

  return html;
}

export function exportarParaJSON(questoes, filename = 'questoes') {
  const data = {
    exportadoEm: new Date().toISOString(),
    total: questoes.length,
    questoes: questoes.map(q => ({
      id: q.id,
      materia: q.materia,
      topico: q.topico,
      banca: q.banca,
      ano: q.ano,
      nivel: q.nivel,
      tipo: q.tipo,
      pergunta: q.pergunta,
      resposta_correta: q.resposta_correta,
      opcoes: q.opcoes.map(o => ({
        letra: o.letra,
        texto: o.texto,
        correta: o.correta,
        justificativa_correta: o.justificativa_correta,
        justificativa_errada: o.justificativa_errada,
      })),
      fonte: q.fonte,
      dispositivo_legal: q.dispositivo_legal,
      tags: q.tags,
    })),
  };

  return JSON.stringify(data, null, 2);
}

export function baixarArquivo(conteudo, nome, tipo = 'text/plain') {
  const blob = new Blob([conteudo], { type: tipo });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = nome;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}

export function exportarDOC(questoes, opcoes = {}) {
  const html = exportarParaHTML(questoes, { ...opcoes, estilo: 'gabarito' });
  const blob = new Blob([html], { type: 'application/msword' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `questoes_${new Date().toISOString().split('T')[0]}.doc`;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}

export function copiarGabarito(questoes) {
  const gabarito = questoes.map((q, idx) => {
    const num = String(idx + 1).padStart(3, '0');
    return `${num} - ${q.resposta_correta || '?'}`;
  }).join('\n');

  navigator.clipboard.writeText(gabarito).then(() => {
    return true;
  }).catch(() => {
    return false;
  });

  return gabarito;
}

import { create } from 'zustand';
import initSqlJs from 'sql.js';

let dbInstance = null;
let initResolve = null;
let initReject = null;

const dbPromise = new Promise((resolve, reject) => {
  initResolve = resolve;
  initReject = reject;
});

export async function initDB() {
  if (dbInstance) return dbInstance;

  try {
    const SQL = await initSqlJs({
      locateFile: file => `https://sql.js.org/dist/${file}`
    });

    const savedData = localStorage.getItem('nexomente_db');
    if (savedData) {
      const data = Uint8Array.from(atob(savedData), c => c.charCodeAt(0));
      dbInstance = new SQL.Database(data);
    } else {
      dbInstance = new SQL.Database();
    }

    createTables(dbInstance);
    initResolve(dbInstance);
    return dbInstance;
  } catch (error) {
    initReject(error);
    throw error;
  }
}

function createTables(db) {
  db.run(`
    CREATE TABLE IF NOT EXISTS pastas (
      id TEXT PRIMARY KEY,
      nome TEXT NOT NULL,
      parent_id TEXT,
      cor TEXT DEFAULT '#6C63FF',
      icone TEXT DEFAULT 'folder',
      created_at TEXT DEFAULT (datetime('now'))
    )
  `);

  db.run(`
    CREATE TABLE IF NOT EXISTS notas (
      id TEXT PRIMARY KEY,
      pasta_id TEXT,
      tipo TEXT NOT NULL CHECK(tipo IN ('livro', 'projeto', 'ideia', 'lembrete', 'diario', 'biblia', 'estudo')),
      titulo TEXT NOT NULL,
      conteudo TEXT,
      tags TEXT DEFAULT '[]',
      criado_em TEXT DEFAULT (datetime('now')),
      atualizado_em TEXT DEFAULT (datetime('now')),
      status TEXT DEFAULT 'ativo',
      autor TEXT,
      pagina_atual INTEGER,
      total_paginas INTEGER,
      avaliacao INTEGER,
      prioridade TEXT,
      data_lembrete TEXT,
      materia TEXT
    )
  `);

  db.run(`
    CREATE TABLE IF NOT EXISTS materias (
      id TEXT PRIMARY KEY,
      nome TEXT NOT NULL,
      cor TEXT NOT NULL,
      icone TEXT DEFAULT 'book',
      meta_horas REAL DEFAULT 0,
      created_at TEXT DEFAULT (datetime('now'))
    )
  `);

  db.run(`
    CREATE TABLE IF NOT EXISTS sessoes_estudo (
      id TEXT PRIMARY KEY,
      materia_id TEXT,
      tipo TEXT NOT NULL CHECK(tipo IN ('pomodoro', 'livre', 'foco')),
      duracao_minutos INTEGER NOT NULL,
      concluida INTEGER DEFAULT 0,
      started_at TEXT,
      ended_at TEXT
    )
  `);

  db.run(`
    CREATE TABLE IF NOT EXISTS flashcards (
      id TEXT PRIMARY KEY,
      nota_id TEXT,
      materia_id TEXT,
      frente TEXT NOT NULL,
      verso TEXT NOT NULL,
      intervalo INTEGER DEFAULT 1,
      repeticoes INTEGER DEFAULT 0,
      ease_factor REAL DEFAULT 2.5,
      next_review TEXT,
      created_at TEXT DEFAULT (datetime('now'))
    )
  `);

  db.run(`
    CREATE TABLE IF NOT EXISTS transacoes_xp (
      id TEXT PRIMARY KEY,
      xp INTEGER NOT NULL,
      motivo TEXT,
      source_type TEXT,
      source_id TEXT,
      created_at TEXT DEFAULT (datetime('now'))
    )
  `);

  const pastas = db.exec("SELECT COUNT(*) as count FROM pastas")[0]?.values[0][0] || 0;
  if (pastas === 0) {
    db.run("INSERT INTO pastas (id, nome, cor, icone) VALUES (?, ?, ?, ?)", 
      ['pasta_raiz', 'Minha Biblioteca', '#6C63FF', 'library']);
  }

  db.run(`
    CREATE VIRTUAL TABLE IF NOT EXISTS notas_fts USING fts5(
      titulo,
      conteudo,
      content='notas',
      content_rowid='rowid'
    )
  `);

  db.run(`
    CREATE TRIGGER IF NOT EXISTS notas_ai AFTER INSERT ON notas BEGIN
      INSERT INTO notas_fts(rowid, titulo, conteudo) VALUES (new.rowid, new.titulo, new.conteudo);
    END
  `);

  db.run(`
    CREATE TRIGGER IF NOT EXISTS notas_ad AFTER DELETE ON notas BEGIN
      INSERT INTO notas_fts(notas_fts, rowid, titulo, conteudo) VALUES('delete', old.rowid, old.titulo, old.conteudo);
    END
  `);

  db.run(`
    CREATE TRIGGER IF NOT EXISTS notas_au AFTER UPDATE ON notas BEGIN
      INSERT INTO notas_fts(notas_fts, rowid, titulo, conteudo) VALUES('delete', old.rowid, old.titulo, old.conteudo);
      INSERT INTO notas_fts(rowid, titulo, conteudo) VALUES (new.rowid, new.titulo, new.conteudo);
    END
  `);

  saveDB();
}

export function saveDB() {
  if (!dbInstance) return;
  const data = dbInstance.export();
  const base64 = btoa(String.fromCharCode.apply(null, data));
  localStorage.setItem('nexomente_db', base64);
}

export function getDB() {
  return dbInstance;
}

export const useDBStore = create((set, get) => ({
  db: null,
  loading: true,
  error: null,

  init: async () => {
    try {
      const db = await initDB();
      set({ db, loading: false });
    } catch (error) {
      set({ error: error.message, loading: false });
    }
  },

 Notas: {
    getAll: () => {
      const db = get().db;
      if (!db) return [];
      const result = db.exec("SELECT * FROM notas WHERE status = 'ativo' ORDER BY atualizado_em DESC");
      if (!result[0]) return [];
      return result[0].values.map(row => ({
        id: row[0],
        pasta_id: row[1],
        tipo: row[2],
        titulo: row[3],
        conteudo: row[4],
        tags: JSON.parse(row[5] || '[]'),
        criado_em: row[6],
        atualizado_em: row[7],
        status: row[8],
      }));
    },

    getById: (id) => {
      const db = get().db;
      if (!db) return null;
      const result = db.exec("SELECT * FROM notas WHERE id = ?", [id]);
      if (!result[0]?.values[0]) return null;
      const row = result[0].values[0];
      return {
        id: row[0],
        pasta_id: row[1],
        tipo: row[2],
        titulo: row[3],
        conteudo: row[4],
        tags: JSON.parse(row[5] || '[]'),
        criado_em: row[6],
        atualizado_em: row[7],
        status: row[8],
      };
    },

    search: (query) => {
      const db = get().db;
      if (!db || !query) return [];
      const result = db.exec(`
        SELECT n.* FROM notas n
        JOIN notas_fts fts ON n.rowid = fts.rowid
        WHERE notas_fts MATCH ?
        AND n.status = 'ativo'
        ORDER BY rank
        LIMIT 50
      `, [query + '*']);
      if (!result[0]) return [];
      return result[0].values.map(row => ({
        id: row[0],
        pasta_id: row[1],
        tipo: row[2],
        titulo: row[3],
        conteudo: row[4],
        tags: JSON.parse(row[5] || '[]'),
        criado_em: row[6],
        atualizado_em: row[7],
        status: row[8],
      }));
    },

    create: (nota) => {
      const db = get().db;
      if (!db) return;
      const id = nota.id || `nota_${Date.now()}`;
      db.run(
        `INSERT INTO notas (id, pasta_id, tipo, titulo, conteudo, tags) VALUES (?, ?, ?, ?, ?, ?)`,
        [id, nota.pasta_id || 'pasta_raiz', nota.tipo || 'nota', nota.titulo, nota.conteudo || '', JSON.stringify(nota.tags || [])]
      );
      saveDB();
      return id;
    },

    update: (id, updates) => {
      const db = get().db;
      if (!db) return;
      const fields = [];
      const values = [];
      if (updates.titulo !== undefined) { fields.push('titulo = ?'); values.push(updates.titulo); }
      if (updates.conteudo !== undefined) { fields.push('conteudo = ?'); values.push(updates.conteudo); }
      if (updates.tags !== undefined) { fields.push('tags = ?'); values.push(JSON.stringify(updates.tags)); }
      fields.push("atualizado_em = datetime('now')");
      values.push(id);
      db.run(`UPDATE notas SET ${fields.join(', ')} WHERE id = ?`, values);
      saveDB();
    },

    delete: (id) => {
      const db = get().db;
      if (!db) return;
      db.run("UPDATE notas SET status = 'deletado' WHERE id = ?", [id]);
      saveDB();
    },
  },

  Pastas: {
    getAll: () => {
      const db = get().db;
      if (!db) return [];
      const result = db.exec("SELECT * FROM pastas ORDER BY nome");
      if (!result[0]) return [];
      return result[0].values.map(row => ({
        id: row[0],
        nome: row[1],
        parent_id: row[2],
        cor: row[3],
        icone: row[4],
        created_at: row[5],
      }));
    },

    create: (pasta) => {
      const db = get().db;
      if (!db) return;
      const id = pasta.id || `pasta_${Date.now()}`;
      db.run(
        "INSERT INTO pastas (id, nome, parent_id, cor, icone) VALUES (?, ?, ?, ?, ?)",
        [id, pasta.nome, pasta.parent_id || null, pasta.cor || '#6C63FF', pasta.icone || 'folder']
      );
      saveDB();
      return id;
    },
  },

  Minas: {
    getAll: () => {
      const db = get().db;
      if (!db) return [];
      const result = db.exec("SELECT * FROM materias ORDER BY nome");
      if (!result[0]) return [];
      return result[0].values.map(row => ({
        id: row[0],
        nome: row[1],
        cor: row[2],
        icone: row[3],
        meta_horas: row[4],
        created_at: row[5],
      }));
    },

    create: (materia) => {
      const db = get().db;
      if (!db) return;
      const id = materia.id || `materia_${Date.now()}`;
      db.run(
        "INSERT INTO materias (id, nome, cor, icone, meta_horas) VALUES (?, ?, ?, ?, ?)",
        [id, materia.nome, materia.cor || '#6C63FF', materia.icone || 'book', materia.meta_horas || 0]
      );
      saveDB();
      return id;
    },
  },

  SessoesEstudo: {
    getAll: () => {
      const db = get().db;
      if (!db) return [];
      const result = db.exec("SELECT * FROM sessoes_estudo ORDER BY started_at DESC LIMIT 50");
      if (!result[0]) return [];
      return result[0].values.map(row => ({
        id: row[0],
        materia_id: row[1],
        tipo: row[2],
        duracao_minutos: row[3],
        concluida: row[4] === 1,
        started_at: row[5],
        ended_at: row[6],
      }));
    },

    create: (sessao) => {
      const db = get().db;
      if (!db) return;
      const id = sessao.id || `sessao_${Date.now()}`;
      db.run(
        "INSERT INTO sessoes_estudo (id, materia_id, tipo, duracao_minutos, started_at) VALUES (?, ?, ?, ?, datetime('now'))",
        [id, sessao.materia_id, sessao.tipo || 'pomodoro', sessao.duracao_minutos || 25]
      );
      saveDB();
      return id;
    },

    completar: (id) => {
      const db = get().db;
      if (!db) return;
      db.run("UPDATE sessoes_estudo SET concluida = 1, ended_at = datetime('now') WHERE id = ?", [id]);
      saveDB();
    },
  },

  Flashcards: {
    getAll: () => {
      const db = get().db;
      if (!db) return [];
      const result = db.exec("SELECT * FROM flashcards ORDER BY created_at DESC");
      if (!result[0]) return [];
      return result[0].values.map(row => ({
        id: row[0],
        nota_id: row[1],
        materia_id: row[2],
        frente: row[3],
        verso: row[4],
        intervalo: row[5],
        repeticoes: row[6],
        ease_factor: row[7],
        next_review: row[8],
        created_at: row[9],
      }));
    },

    getParaRevisao: () => {
      const db = get().db;
      if (!db) return [];
      const result = db.exec("SELECT * FROM flashcards WHERE next_review IS NULL OR next_review <= datetime('now') ORDER BY next_review");
      if (!result[0]) return [];
      return result[0].values.map(row => ({
        id: row[0],
        nota_id: row[1],
        materia_id: row[2],
        frente: row[3],
        verso: row[4],
        intervalo: row[5],
        repeticoes: row[6],
        ease_factor: row[7],
        next_review: row[8],
      }));
    },

    create: (card) => {
      const db = get().db;
      if (!db) return;
      const id = card.id || `fc_${Date.now()}`;
      db.run(
        "INSERT INTO flashcards (id, nota_id, materia_id, frente, verso) VALUES (?, ?, ?, ?)",
        [id, card.nota_id, card.materia_id, card.frente, card.verso]
      );
      saveDB();
      return id;
    },

    revisar: (id, qualidade) => {
      const db = get().db;
      if (!db) return;

      const result = db.exec("SELECT intervalo, repeticoes, ease_factor FROM flashcards WHERE id = ?", [id]);
      if (!result[0]?.values[0]) return;

      let [intervalo, repeticoes, ease_factor] = result[0].values[0];
      repeticoes = repeticoes || 0;
      ease_factor = ease_factor || 2.5;

      if (qualidade >= 3) {
        if (repeticoes === 0) intervalo = 1;
        else if (repeticoes === 1) intervalo = 6;
        else intervalo = Math.round(intervalo * ease_factor);
        repeticoes += 1;
      } else {
        repeticoes = 0;
        intervalo = 1;
      }

      ease_factor = ease_factor + (0.1 - (5 - qualidade) * (0.08 + (5 - qualidade) * 0.02));
      if (ease_factor < 1.3) ease_factor = 1.3;

      db.run(
        "UPDATE flashcards SET intervalo = ?, repeticoes = ?, ease_factor = ?, next_review = datetime('now', ? || ' days') WHERE id = ?",
        [intervalo, repeticoes, ease_factor, intervalo, id]
      );
      saveDB();
    },
  },

  XP: {
    getTotal: () => {
      const db = get().db;
      if (!db) return 0;
      const result = db.exec("SELECT COALESCE(SUM(xp), 0) FROM transacoes_xp");
      return result[0]?.values[0][0] || 0;
    },

    add: (xp, motivo, source_type, source_id) => {
      const db = get().db;
      if (!db) return;
      const id = `xp_${Date.now()}`;
      db.run(
        "INSERT INTO transacoes_xp (id, xp, motivo, source_type, source_id) VALUES (?, ?, ?, ?, ?)",
        [id, xp, motivo, source_type, source_id]
      );
      saveDB();
    },
  },
}));

